     1→// ==================== ENUMS / LITERALS ====================
     2→
     3→export type Trend = 'BULLISH' | 'BEARISH' | 'RANGING';
     4→export type Zone = 'PREMIUM' | 'DISCOUNT' | 'EQUILIBRIUM';
     5→export type Direction = 'LONG' | 'SHORT';
     6→export type EntryType = 'FVG' | 'ORDER_BLOCK' | 'OTE';
     7→export type SessionStatus = 'ACTIVE' | 'HALTED' | 'NO_TRADE_ZONE';
     8→export type ScoreGrade = 'A+' | 'A' | 'B+' | 'B' | 'C' | 'DISQUALIFIED';
     9→
    10→export type KillZoneName =
    11→  | 'ASIAN'
    12→  | 'LONDON_OPEN'
    13→  | 'NY_OPEN'
    14→  | 'SILVER_BULLET_AM'
    15→  | 'SILVER_BULLET_PM'
    16→  | 'NONE';
    17→
    18→export type LiquidityType =
    19→  | 'BSL'
    20→  | 'SSL'
    21→  | 'EQH'
    22→  | 'EQL'
    23→  | 'PWH'
    24→  | 'PWL'
    25→  | 'PDH'
    26→  | 'PDL'
    27→  | 'ASIAN_HIGH'
    28→  | 'ASIAN_LOW';
    29→
    30→export type LiquidityRank = 'S+' | 'S' | 'A+' | 'A' | 'B+' | 'B' | 'C' | 'D';
    31→
    32→// ==================== MARKET DATA ====================
    33→
    34→export interface Candle {
    35→  readonly timestamp: number;
    36→  readonly open: number;
    37→  readonly high: number;
    38→  readonly low: number;
    39→  readonly close: number;
    40→  readonly volume: number;
    41→}
    42→
    43→// ==================== STRUCTURE ====================
    44→
    45→export interface SwingPoint {
    46→  readonly timestamp: number;
    47→  readonly price: number;
    48→  readonly index: number;
    49→  readonly type: 'HIGH' | 'LOW';
    50→  readonly strength: number;
    51→  readonly mitigated: boolean;
    52→}
    53→
    54→export interface StructureBreak {
    55→  readonly type: 'BOS' | 'MSS';
    56→  readonly direction: Direction;
    57→  readonly level: number;
    58→  readonly index: number;
    59→  readonly timestamp: number;
    60→}
    61→
    62→export interface DealingRange {
    63→  readonly high: number;
    64→  readonly low: number;
    65→  readonly equilibrium: number;
    66→  readonly premium: { readonly upper: number; readonly lower: number };
    67→  readonly discount: { readonly upper: number; readonly lower: number };
    68→  readonly ote: { readonly upper: number; readonly lower: number };
    69→}
    70→
    71→// ==================== LIQUIDITY ====================
    72→
    73→export interface LiquidityLevel {
    74→  readonly price: number;
    75→  readonly type: LiquidityType;
    76→  readonly rank: LiquidityRank;
    77→  readonly weight: number;
    78→  readonly swept: boolean;
    79→  readonly sweepTimestamp?: number;
    80→}
    81→
    82→export interface LiquiditySweep {
    83→  readonly level: LiquidityLevel;
    84→  readonly sweepCandle: Candle;
    85→  readonly sweepIndex: number;
    86→  readonly penetrationDepth: number;
    87→  readonly reintegrated: boolean;
    88→  readonly reintegrationSpeed: number;
    89→}
    90→
    91→// ==================== ENTRY ZONES ====================
    92→
    93→export interface FairValueGap {
    94→  readonly high: number;
    95→  readonly low: number;
    96→  readonly midpoint: number;
    97→  readonly size: number;
    98→  readonly direction: Direction;
    99→  readonly timestamp: number;
   100→  readonly index: number;
   101→  readonly fillPercent: number;
   102→  readonly isValid: boolean;
   103→}
   104→
   105→export interface OrderBlock {
   106→  readonly high: number;
   107→  readonly low: number;
   108→  readonly open: number;
   109→  readonly close: number;
   110→  readonly timestamp: number;
   111→  readonly index: number;
   112→  readonly direction: Direction;
   113→  readonly confirmed: boolean;
   114→  readonly mitigated: boolean;
   115→}
   116→
   117→// ==================== AMD ====================
   118→
   119→export interface AMDPattern {
   120→  readonly phase: 'ACCUMULATION' | 'MANIPULATION' | 'DISTRIBUTION' | 'NONE';
   121→  readonly accumulationRange?: { readonly high: number; readonly low: number };
   122→  readonly manipulationSweep?: {
   123→    readonly level: LiquidityLevel;
   124→    readonly sweepCandle: Candle;
   125→    readonly penetrationDepth: number;
   126→  };
   127→  readonly distributionTarget?: number;
   128→  readonly confirmed: boolean;
   129→}
   130→
   131→// ==================== CONTEXT ====================
   132→
   133→export interface HTFContext {
   134→  readonly d1: {
   135→    readonly trend: Trend;
   136→    readonly structure: 'HH_HL' | 'LH_LL' | 'RANGING';
   137→  };
   138→  readonly h4: {
   139→    readonly bias: Direction;
   140→    readonly lastBOS: StructureBreak | null;
   141→    readonly activeOB?: OrderBlock;
   142→  };
   143→  readonly h1: {
   144→    readonly swingHigh: number;
   145→    readonly swingLow: number;
   146→    readonly activeFVG?: FairValueGap;
   147→  };
   148→}
   149→
   150→export interface MacroContext {
   151→  readonly dxy: {
   152→    readonly trend: Trend;
   153→    readonly implication: Direction | 'NEUTRAL';
   154→  };
   155→  readonly vix: {
   156→    readonly level: number;
   157→    readonly interpretation: 'CALM' | 'NORMAL' | 'ELEVATED' | 'STRESS' | 'PANIC';
   158→    readonly sizingMultiplier: number;
   159→  };
   160→  readonly newsFilter: {
   161→    readonly highImpactToday: boolean;
   162→    readonly noTradeWindow: boolean;
   163→  };
   164→  readonly sentiment?: {
   165→    readonly retailLongPercent: number;
   166→    readonly contrarianSignal: Direction | 'NONE';
   167→  };
   168→}
   169→
   170→// ==================== SCORING ====================
   171→
   172→export interface SetupScore {
   173→  readonly structureAlignment: number;
   174→  readonly judasSwingQuality: number;
   175→  readonly entryQuality: number;
   176→  readonly macroContext: number;
   177→  readonly total: number;
   178→  readonly grade: ScoreGrade;
   179→  readonly sizing: number;
   180→  readonly tradeable: boolean;
   181→}
   182→
   183→// ==================== ENTRY PARAMETERS ====================
   184→
   185→export interface PartialExit {
   186→  readonly level: number;
   187→  readonly percent: number;
   188→  readonly rMultiple: number;
   189→}
   190→
   191→export interface TrailingStopConfig {
   192→  readonly activationR: number;
   193→  readonly trailDistance: number;
   194→  readonly stepSize: number;
   195→}
   196→
   197→export interface EntryParams {
   198→  readonly type: EntryType;
   199→  readonly price: number;
   200→  readonly stopLoss: number;
   201→  readonly slDistance: number;
   202→  readonly tp1: number;
   203→  readonly tp2: number;
   204→  readonly tp3: number;
   205→  readonly riskReward: number;
   206→  readonly positionSize: number;
   207→  readonly riskAmount: number;
   208→  readonly riskPercent: number;
   209→  readonly partialExits: readonly PartialExit[];
   210→  readonly trailingStop: TrailingStopConfig;
   211→}
   212→
   213→// ==================== SIGNAL RESULT ====================
   214→
   215→export interface SignalResult {
   216→  readonly isTradable: boolean;
   217→  readonly direction: Direction;
   218→  readonly timestamp: number;
   219→  readonly context: {
   220→    readonly htfBias: Trend;
   221→    readonly htfAligned: boolean;
   222→    readonly zone: Zone;
   223→    readonly zoneValid: boolean;
   224→    readonly killZone: KillZoneName;
   225→    readonly killZoneActive: boolean;
   226→    readonly amd: AMDPattern;
   227→    readonly macro: MacroContext;
   228→  };
   229→  readonly liquidity: {
   230→    readonly sweepConfirmed: boolean;
   231→    readonly levelSwept: LiquidityLevel | null;
   232→    readonly targets: readonly LiquidityLevel[];
   233→  };
   234→  readonly entry: EntryParams | null;
   235→  readonly score: SetupScore;
   236→  readonly disqualifications: readonly string[];
   237→  readonly sessionStatus: SessionStatus;
   238→}
   239→
   240→// ==================== CONFIGURATION ====================
   241→
   242→export interface InstrumentConfig {
   243→  readonly symbol: string;
   244→  readonly maxSLPoints: number;
   245→  readonly pointValue: number;
   246→  readonly minFVGSize: number;
   247→  readonly spread: number;
   248→}
   249→
   250→export interface RiskConfig {
   251→  readonly maxRiskPerTrade: number;
   252→  readonly maxDailyDrawdown: number;
   253→  readonly maxWeeklyDrawdown: number;
   254→  readonly maxConsecutiveLosses: number;
   255→  readonly maxTradesPerDay: number;
   256→}
   257→
   258→export interface AnalysisConfig {
   259→  readonly instrument: InstrumentConfig;
   260→  readonly risk: RiskConfig;
   261→  readonly capital: number;
   262→  readonly swingLookback: number;
   263→}
   264→
   265→export interface SessionState {
   266→  consecutiveLosses: number;
   267→  dailyPnL: number;
   268→  weeklyPnL: number;
   269→  tradesCount: number;
   270→  isHalted: boolean;
   271→  haltReason?: string;
   272→  date: string;
   273→}
   274→
   275→// ==================== KILL ZONE CONFIG ====================
   276→
   277→export interface KillZoneConfig {
   278→  readonly name: KillZoneName;
   279→  readonly start: number;
   280→  readonly end: number;
   281→  readonly quality: number;
   282→  readonly allowed: boolean;
   283→}
   284→
   285→export interface NoTradeZoneConfig {
   286→  readonly name: string;
   287→  readonly start: number;
   288→  readonly end: number;
   289→}
   290→

