     1→import type {
     2→  Candle,
     3→  SignalResult,
     4→  MacroContext,
     5→  Direction,
     6→  Trend,
     7→  Zone,
     8→  KillZoneName,
     9→  RiskConfig,
    10→  AnalysisConfig,
    11→  LiquidityLevel,
    12→  EntryParams,
    13→  SessionStatus,
    14→} from '../core/types.js';
    15→import { MarketStructure } from '../analysis/MarketStructure.js';
    16→import { LiquidityAnalyzer } from '../analysis/LiquidityAnalyzer.js';
    17→import { EntryDetector } from '../analysis/EntryDetector.js';
    18→import { AMDDetector } from '../analysis/AMDDetector.js';
    19→import { KillZoneManager } from '../analysis/KillZoneManager.js';
    20→import { Indicators } from '../analysis/Indicators.js';
    21→import { SetupScorer } from '../scoring/SetupScorer.js';
    22→import { RiskCalculator } from '../scoring/RiskCalculator.js';
    23→import { SessionManager } from './SessionManager.js';
    24→import { validateCandles, buildAnalysisConfig } from '../utils/validation.js';
    25→import * as time from '../utils/time.js';
    26→
    27→/**
    28→ * SMCAnalyzer — Main orchestrator for the SMC trading engine.
    29→ *
    30→ * Runs a 14-step analysis pipeline:
    31→ *  1. Validate inputs
    32→ *  2. Check session status (circuit breaker)
    33→ *  3. Check kill zone
    34→ *  4. Analyze HTF structure and bias (reject RANGING)
    35→ *  5. Calculate dealing range and zone
    36→ *  6. Compute technical indicators (VWAP, EMA, RSI, VP, CVD)
    37→ *  7. Map liquidity levels
    38→ *  8. Detect sweeps
    39→ *  9. Detect AMD pattern
    40→ * 10. Detect entry triggers (FVG/OB)
    41→ * 11. Calculate score with indicator confluence
    42→ * 12. Calculate entry parameters (with partial exits + trailing stop)
    43→ * 13. Build final SignalResult
    44→ * 14. Return
    45→ */
    46→export class SMCAnalyzer {
    47→  private readonly config: AnalysisConfig;
    48→  private readonly marketStructure: MarketStructure;
    49→  private readonly liquidityAnalyzer: LiquidityAnalyzer;
    50→  private readonly entryDetector: EntryDetector;
    51→  private readonly amdDetector: AMDDetector;
    52→  private readonly killZoneManager: KillZoneManager;
    53→  private readonly indicators: Indicators;
    54→  private readonly setupScorer: SetupScorer;
    55→  private readonly riskCalculator: RiskCalculator;
    56→  private readonly sessionManager: SessionManager;
    57→
    58→  constructor(symbol: string, capital: number, riskConfig?: Partial<RiskConfig>) {
    59→    this.config = buildAnalysisConfig(symbol, capital, riskConfig as RiskConfig | undefined);
    60→    this.marketStructure = new MarketStructure(this.config.swingLookback);
    61→    this.liquidityAnalyzer = new LiquidityAnalyzer();
    62→    this.entryDetector = new EntryDetector(this.config.instrument.minFVGSize);
    63→    this.amdDetector = new AMDDetector();
    64→    this.killZoneManager = new KillZoneManager();
    65→    this.indicators = new Indicators();
    66→    this.setupScorer = new SetupScorer();
    67→    this.riskCalculator = new RiskCalculator();
    68→    this.sessionManager = new SessionManager(this.config.risk, this.config.capital);
    69→  }
    70→
    71→  /**
    72→   * Main analysis pipeline.
    73→   * Takes LTF candle data, HTF candle data, and macro context.
    74→   * Returns a complete SignalResult with tradeability assessment.
    75→   */
    76→  analyze(
    77→    ltfCandles: readonly Candle[],
    78→    htfCandles: readonly Candle[],
    79→    macro: MacroContext,
    80→  ): SignalResult {
    81→    try {
    82→      // Step 1: Validate inputs
    83→      validateCandles(ltfCandles);
    84→      validateCandles(htfCandles);
    85→
    86→      const lastCandle = ltfCandles[ltfCandles.length - 1]!;
    87→      const timestamp = lastCandle.timestamp;
    88→      const currentPrice = lastCandle.close;
    89→
    90→      // Step 2: Check session status
    91→      const sessionStatus = this.sessionManager.checkSessionStatus(timestamp);
    92→      const tradeCheck = this.sessionManager.canTakeNewTrade();
    93→
    94→      if (sessionStatus === 'HALTED' || !tradeCheck.allowed) {
    95→        return this.buildNoTradeResult(
    96→          timestamp,
    97→          currentPrice,
    98→          macro,
    99→          sessionStatus === 'HALTED' ? 'HALTED' : 'ACTIVE',
   100→          [tradeCheck.reason],
   101→        );
   102→      }
   103→
   104→      // Step 3: Check kill zone
   105→      const kzInfo = this.killZoneManager.getCurrentKillZone(timestamp);
   106→      const tradingAllowed = this.killZoneManager.isTradingAllowed(timestamp);
   107→      const killZoneName: KillZoneName = kzInfo?.name ?? 'NONE';
   108→
   109→      if (!tradingAllowed.allowed) {
   110→        return this.buildNoTradeResult(
   111→          timestamp,
   112→          currentPrice,
   113→          macro,
   114→          'NO_TRADE_ZONE',
   115→          [tradingAllowed.reason],
   116→        );
   117→      }
   118→
   119→      // Step 4: Analyze HTF structure
   120→      const htfSwings = this.marketStructure.identifySwingPoints(htfCandles);
   121→      const htfTrend = this.marketStructure.determineTrend(htfSwings);
   122→
   123→      // RANGING = no directional bias → no trade
   124→      if (htfTrend === 'RANGING') {
   125→        return this.buildNoTradeResult(
   126→          timestamp,
   127→          currentPrice,
   128→          macro,
   129→          'ACTIVE',
   130→          ['HTF trend is RANGING — no directional bias'],
   131→        );
   132→      }
   133→
   134→      const direction: Direction = htfTrend === 'BULLISH' ? 'LONG' : 'SHORT';
   135→
   136→      // Step 5: Calculate dealing range and zone
   137→      const ltfSwings = this.marketStructure.identifySwingPoints(ltfCandles);
   138→      const dealingRange = this.marketStructure.calculateDealingRange(ltfSwings);
   139→
   140→      let zone: Zone = 'EQUILIBRIUM';
   141→      let zoneValid = false;
   142→      let isInOTE = false;
   143→
   144→      if (dealingRange) {
   145→        zone = this.marketStructure.getZone(currentPrice, dealingRange);
   146→        zoneValid = this.marketStructure.isZoneValid(zone, direction);
   147→        isInOTE = this.marketStructure.isInOTE(currentPrice, dealingRange);
   148→      }
   149→
   150→      const htfAligned = this.isHTFAligned(htfTrend, direction);
   151→
   152→      // Step 6: Compute technical indicators
   153→      const indicatorSnapshot = this.indicators.computeAll(ltfCandles);
   154→
   155→      // Step 7: Map liquidity levels
   156→      const liquidityLevels = this.liquidityAnalyzer.mapAllLevels(
   157→        ltfCandles,
   158→        ltfSwings,
   159→        timestamp,
   160→      );
   161→
   162→      // Step 8: Detect sweeps
   163→      const sweeps = this.liquidityAnalyzer.detectSweeps(ltfCandles, liquidityLevels);
   164→      const bestSweep = sweeps.length > 0 ? sweeps[sweeps.length - 1]! : null;
   165→
   166→      // Step 9: Detect AMD pattern
   167→      const asianRange = time.getAsianSessionRange(ltfCandles, timestamp);
   168→      const amd = this.amdDetector.detectAMD(ltfCandles, sweeps, asianRange, liquidityLevels);
   169→
   170→      // Step 10: Detect entry triggers (FVG/OB)
   171→      const fvgs = this.entryDetector.detectFVG(ltfCandles);
   172→      const updatedFVGs = this.entryDetector.updateFVGFillStatus(fvgs, ltfCandles);
   173→      const obs = this.entryDetector.detectOrderBlocks(ltfCandles, ltfSwings);
   174→      const updatedOBs = this.entryDetector.updateOBMitigation(obs, ltfCandles);
   175→
   176→      const bestEntry = this.entryDetector.findBestEntry(updatedFVGs, updatedOBs, direction);
   177→      const hasOverlap = bestEntry.hasOverlap;
   178→
   179→      // Step 11: Calculate score with indicator confluence
   180→      const scoreInput = {
   181→        htfTrend,
   182→        htfAligned,
   183→        zone,
   184→        zoneValid,
   185→        direction,
   186→        dealingRange,
   187→        currentPrice,
   188→        sweep: bestSweep,
   189→        amd,
   190→        fvg: bestEntry.fvg,
   191→        ob: bestEntry.ob,
   192→        fvgObOverlap: hasOverlap,
   193→        killZone: killZoneName,
   194→        killZoneQuality: kzInfo?.quality ?? 0,
   195→        macro,
   196→        isInOTE,
   197→        indicators: indicatorSnapshot,
   198→      };
   199→
   200→      const score = this.setupScorer.calculateScore(scoreInput);
   201→      const disqualifications = this.setupScorer.checkDisqualifications(scoreInput);
   202→
   203→      // Step 12: Calculate entry parameters
   204→      let entry: EntryParams | null = null;
   205→
   206→      if (score.tradeable && disqualifications.length === 0) {
   207→        const opposingTargets = this.getOpposingTargets(direction, liquidityLevels);
   208→
   209→        entry = this.riskCalculator.calculateEntryParams(
   210→          direction,
   211→          bestEntry.fvg,
   212→          bestEntry.ob,
   213→          amd,
   214→          opposingTargets,
   215→          dealingRange,
   216→          this.config.instrument,
   217→          this.config.capital,
   218→          this.config.risk.maxRiskPerTrade,
   219→          score.sizing,
   220→          macro.vix.sizingMultiplier,
   221→        );
   222→      }
   223→
   224→      // Step 13: Build final signal result
   225→      const isTradable = entry !== null && score.tradeable && disqualifications.length === 0;
   226→
   227→      return {
   228→        isTradable,
   229→        direction,
   230→        timestamp,
   231→        context: {
   232→          htfBias: htfTrend,
   233→          htfAligned,
   234→          zone,
   235→          zoneValid,
   236→          killZone: killZoneName,
   237→          killZoneActive: kzInfo !== null,
   238→          amd,
   239→          macro,
   240→        },
   241→        liquidity: {
   242→          sweepConfirmed: bestSweep !== null,
   243→          levelSwept: bestSweep?.level ?? null,
   244→          targets: this.getOpposingTargets(direction, liquidityLevels),
   245→        },
   246→        entry,
   247→        score,
   248→        disqualifications,
   249→        sessionStatus: 'ACTIVE',
   250→      };
   251→    } catch (error) {
   252→      const msg = error instanceof Error ? error.message : 'Unknown analysis error';
   253→      return this.buildErrorResult(msg);
   254→    }
   255→  }
   256→
   257→  /** Record a trade outcome for session management */
   258→  recordTradeResult(result: 'WIN' | 'LOSS' | 'BE', pnl: number): void {
   259→    this.sessionManager.updateAfterTrade(result, pnl);
   260→  }
   261→
   262→  /** Get current session state */
   263→  getSessionState() {
   264→    return this.sessionManager.getState();
   265→  }
   266→
   267→  /** Reset the session for a new trading day */
   268→  resetSession(date?: string): void {
   269→    this.sessionManager.resetDaily(date);
   270→  }
   271→
   272→  /** Reset the session for a new trading week */
   273→  resetWeeklySession(date?: string): void {
   274→    this.sessionManager.resetWeekly(date);
   275→  }
   276→
   277→  private isHTFAligned(htfTrend: Trend, direction: Direction): boolean {
   278→    if (htfTrend === 'RANGING') return false;
   279→    if (direction === 'LONG' && htfTrend === 'BULLISH') return true;
   280→    if (direction === 'SHORT' && htfTrend === 'BEARISH') return true;
   281→    return false;
   282→  }
   283→
   284→  private getOpposingTargets(
   285→    direction: Direction,
   286→    levels: readonly LiquidityLevel[],
   287→  ): LiquidityLevel[] {
   288→    if (direction === 'LONG') {
   289→      return levels.filter(l =>
   290→        ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(l.type) && !l.swept,
   291→      );
   292→    }
   293→    return levels.filter(l =>
   294→      ['SSL', 'EQL', 'PWL', 'PDL', 'ASIAN_LOW'].includes(l.type) && !l.swept,
   295→    );
   296→  }
   297→
   298→  private buildNoTradeResult(
   299→    timestamp: number,
   300→    _currentPrice: number,
   301→    macro: MacroContext,
   302→    sessionStatus: SessionStatus,
   303→    disqualifications: string[],
   304→  ): SignalResult {
   305→    return {
   306→      isTradable: false,
   307→      direction: 'LONG',
   308→      timestamp,
   309→      context: {
   310→        htfBias: 'RANGING',
   311→        htfAligned: false,
