     1→import type { SessionState, SessionStatus, RiskConfig } from '../core/types.js';
     2→import { DEFAULT_RISK } from '../core/constants.js';
     3→import * as math from '../utils/math.js';
     4→import * as time from '../utils/time.js';
     5→
     6→/**
     7→ * SessionManager — Circuit breaker, daily trade limits, and session state tracking.
     8→ *
     9→ * Halts trading after:
    10→ * - N consecutive losses (default 2)
    11→ * - Daily drawdown >= threshold (default 2% of capital)
    12→ * - Weekly drawdown >= threshold (default 5% of capital)
    13→ * - Max trades per day reached
    14→ *
    15→ * Resets automatically at NY midnight.
    16→ */
    17→export class SessionManager {
    18→  private state: SessionState;
    19→  private readonly riskConfig: RiskConfig;
    20→  private readonly capital: number;
    21→
    22→  constructor(riskConfig?: RiskConfig, capital: number = 100000) {
    23→    this.riskConfig = riskConfig ?? DEFAULT_RISK;
    24→    this.capital = capital;
    25→    this.state = this.createFreshState();
    26→  }
    27→
    28→  /** Check if the session allows a new trade */
    29→  checkSessionStatus(timestamp?: number): SessionStatus {
    30→    // Auto-reset if it's a new day
    31→    if (timestamp) {
    32→      const currentDate = time.getSessionDate(timestamp);
    33→      if (currentDate !== this.state.date) {
    34→        this.resetDaily(currentDate);
    35→      }
    36→    }
    37→
    38→    if (this.state.isHalted) return 'HALTED';
    39→
    40→    if (timestamp && !time.isTradingTime(timestamp)) {
    41→      return 'NO_TRADE_ZONE';
    42→    }
    43→
    44→    return 'ACTIVE';
    45→  }
    46→
    47→  /** Record a trade result and update session state */
    48→  updateAfterTrade(result: 'WIN' | 'LOSS' | 'BE', pnl: number): void {
    49→    this.state.tradesCount++;
    50→    this.state.dailyPnL = math.add(this.state.dailyPnL, pnl);
    51→    this.state.weeklyPnL = math.add(this.state.weeklyPnL, pnl);
    52→
    53→    if (result === 'LOSS') {
    54→      this.state.consecutiveLosses++;
    55→    } else {
    56→      this.state.consecutiveLosses = 0;
    57→    }
    58→
    59→    // Check circuit breaker conditions
    60→    this.checkCircuitBreaker();
    61→  }
    62→
    63→  /** Reset session state for a new trading day */
    64→  resetDaily(date?: string): void {
    65→    const weeklyPnL = this.state.weeklyPnL;
    66→    this.state = this.createFreshState(date);
    67→    // Preserve weekly P&L across daily resets
    68→    this.state.weeklyPnL = weeklyPnL;
    69→  }
    70→
    71→  /** Reset weekly state (call at start of new week) */
    72→  resetWeekly(date?: string): void {
    73→    this.state = this.createFreshState(date);
    74→  }
    75→
    76→  /** Check if session is halted */
    77→  isHalted(): boolean {
    78→    return this.state.isHalted;
    79→  }
    80→
    81→  /** Get the halt reason if session is halted */
    82→  getHaltReason(): string | undefined {
    83→    return this.state.haltReason;
    84→  }
    85→
    86→  /** Get a readonly snapshot of session state */
    87→  getState(): Readonly<SessionState> {
    88→    return { ...this.state };
    89→  }
    90→
    91→  /** Check if we can take another trade (under daily limit) */
    92→  canTakeNewTrade(): { allowed: boolean; reason: string } {
    93→    if (this.state.isHalted) {
    94→      return { allowed: false, reason: this.state.haltReason ?? 'Session halted' };
    95→    }
    96→
    97→    if (this.state.tradesCount >= this.riskConfig.maxTradesPerDay) {
    98→      return { allowed: false, reason: `Daily trade limit reached (${this.riskConfig.maxTradesPerDay})` };
    99→    }
   100→
   101→    return { allowed: true, reason: 'Session active' };
   102→  }
   103→
   104→  /** Check circuit breaker conditions and halt if triggered */
   105→  private checkCircuitBreaker(): void {
   106→    // Consecutive losses
   107→    if (this.state.consecutiveLosses >= this.riskConfig.maxConsecutiveLosses) {
   108→      this.state.isHalted = true;
   109→      this.state.haltReason = `Circuit breaker: ${this.state.consecutiveLosses} consecutive losses`;
   110→      return;
   111→    }
   112→
   113→    // Daily trade limit
   114→    if (this.state.tradesCount >= this.riskConfig.maxTradesPerDay) {
   115→      this.state.isHalted = true;
   116→      this.state.haltReason = `Daily trade limit reached (${this.riskConfig.maxTradesPerDay})`;
   117→      return;
   118→    }
   119→
   120→    // Daily drawdown — compare PnL as percentage of capital
   121→    if (this.state.dailyPnL < 0) {
   122→      const drawdownPct = math.div(Math.abs(this.state.dailyPnL), this.capital);
   123→      if (drawdownPct >= this.riskConfig.maxDailyDrawdown) {
   124→        this.state.isHalted = true;
   125→        this.state.haltReason = `Daily drawdown limit reached (${math.roundTo(math.mul(drawdownPct, 100), 2)}% of capital)`;
   126→        return;
   127→      }
   128→    }
   129→
   130→    // Weekly drawdown — compare PnL as percentage of capital
   131→    if (this.state.weeklyPnL < 0) {
   132→      const weeklyDrawdownPct = math.div(Math.abs(this.state.weeklyPnL), this.capital);
   133→      if (weeklyDrawdownPct >= this.riskConfig.maxWeeklyDrawdown) {
   134→        this.state.isHalted = true;
   135→        this.state.haltReason = `Weekly drawdown limit reached (${math.roundTo(math.mul(weeklyDrawdownPct, 100), 2)}% of capital)`;
   136→        return;
   137→      }
   138→    }
   139→  }
   140→
   141→  /** Create a fresh session state */
   142→  private createFreshState(date?: string): SessionState {
   143→    return {
   144→      consecutiveLosses: 0,
   145→      dailyPnL: 0,
   146→      weeklyPnL: 0,
   147→      tradesCount: 0,
   148→      isHalted: false,
   149→      haltReason: undefined,
   150→      date: date ?? new Date().toISOString().slice(0, 10),
   151→    };
   152→  }
   153→}
