     6→/** Add two numbers with decimal precision */
     7→export function add(a: number, b: number): number {
     8→  return new Decimal(a).plus(b).toNumber();
     9→}
    10→
    11→/** Subtract b from a with decimal precision */
    12→export function sub(a: number, b: number): number {
    13→  return new Decimal(a).minus(b).toNumber();
    14→}
    15→
    16→/** Multiply two numbers with decimal precision */
    17→export function mul(a: number, b: number): number {
    18→  return new Decimal(a).times(b).toNumber();
    19→}
    20→
    21→/** Divide a by b with decimal precision */
    22→export function div(a: number, b: number): number {
    23→  if (b === 0) return 0;
    24→  return new Decimal(a).dividedBy(b).toNumber();
    25→}
    26→
    27→/** Absolute value */
    28→export function abs(a: number): number {
    29→  return new Decimal(a).abs().toNumber();
    30→}
    31→
    32→/** Calculate midpoint between two prices */
    33→export function midpoint(a: number, b: number): number {
    34→  return new Decimal(a).plus(b).dividedBy(2).toNumber();
    35→}
    36→
    37→/** Calculate percentage change from a to b */
    38→export function percentChange(from: number, to: number): number {
    39→  if (from === 0) return 0;
    40→  return new Decimal(to).minus(from).dividedBy(new Decimal(from).abs()).times(100).toNumber();
    41→}
    42→
    43→/** Calculate fibonacci retracement level: high - (high - low) * ratio */
    44→export function fibLevel(high: number, low: number, ratio: number): number {
    45→  const range = new Decimal(high).minus(low);
    46→  return new Decimal(high).minus(range.times(ratio)).toNumber();
    47→}
    48→
    49→/** Calculate distance in points between two prices */
    50→export function pointsDistance(a: number, b: number): number {
    51→  return new Decimal(a).minus(b).abs().toNumber();
    52→}
    53→
    54→/**
    55→ * Check if two prices are approximately equal within a tolerance.
    56→ * Used for detecting equal highs / equal lows.
    57→ */
    58→export function isApproxEqual(a: number, b: number, tolerance: number): boolean {
    59→  return new Decimal(a).minus(b).abs().lte(tolerance);
    60→}
    61→
    62→/** Check if a > b with decimal precision */
    63→export function isGreater(a: number, b: number): boolean {
    64→  return new Decimal(a).greaterThan(b);
    65→}
    66→
    67→/** Check if a < b with decimal precision */
    68→export function isLess(a: number, b: number): boolean {
    69→  return new Decimal(a).lessThan(b);
    70→}
    71→
    72→/** Check if a >= b with decimal precision */
    73→export function isGte(a: number, b: number): boolean {
    74→  return new Decimal(a).greaterThanOrEqualTo(b);
    75→}
    76→
    77→/** Check if a <= b with decimal precision */
    78→export function isLte(a: number, b: number): boolean {
    79→  return new Decimal(a).lessThanOrEqualTo(b);
    80→}
    81→
    82→/** Round to a specific number of decimal places */
    83→export function roundTo(value: number, decimals: number): number {
    84→  return new Decimal(value).toDecimalPlaces(decimals).toNumber();
    85→}
    86→
    87→/**
    88→ * Calculate Average True Range over a period.
    89→ * TR = max(H-L, |H-prevC|, |L-prevC|)
    90→ */
    91→export function atr(candles: readonly Candle[], period: number): number {
    92→  if (candles.length < 2) return 0;
    93→  const effectivePeriod = Math.min(period, candles.length - 1);
    94→  let sum = new Decimal(0);
    95→
    96→  for (let i = candles.length - effectivePeriod; i < candles.length; i++) {
    97→    const candle = candles[i]!;
    98→    const prev = candles[i - 1]!;
    99→    const hl = new Decimal(candle.high).minus(candle.low);
   100→    const hpc = new Decimal(candle.high).minus(prev.close).abs();
   101→    const lpc = new Decimal(candle.low).minus(prev.close).abs();
   102→    sum = sum.plus(Decimal.max(hl, hpc, lpc));
   103→  }
   104→
   105→  return sum.dividedBy(effectivePeriod).toNumber();
   106→}
   107→
   108→/** Find the minimum value from an array of numbers */
   109→export function min(...values: number[]): number {
   110→  return Decimal.min(...values.map(v => new Decimal(v))).toNumber();
   111→}
   112→
   113→/** Find the maximum value from an array of numbers */
   114→export function max(...values: number[]): number {
   115→  return Decimal.max(...values.map(v => new Decimal(v))).toNumber();
   116→}
