     5→/**
     6→ * Validate an array of candles for correctness.
     7→ * Checks OHLC relationships, ascending timestamps, and valid values.
     8→ */
     9→export function validateCandles(candles: readonly Candle[]): void {
    10→  if (!Array.isArray(candles) || candles.length === 0) {
    11→    throw new ValidationError('Candles array must be non-empty', 'candles');
    12→  }
    13→
    14→  for (let i = 0; i < candles.length; i++) {
    15→    const c = candles[i]!;
    16→
    17→    if (typeof c.timestamp !== 'number' || !isFinite(c.timestamp) || c.timestamp <= 0) {
    18→      throw new ValidationError(`Invalid timestamp at index ${i}`, 'candles.timestamp');
    19→    }
    20→    if (typeof c.open !== 'number' || !isFinite(c.open) || c.open <= 0) {
    21→      throw new ValidationError(`Invalid open at index ${i}`, 'candles.open');
    22→    }
    23→    if (typeof c.high !== 'number' || !isFinite(c.high) || c.high <= 0) {
    24→      throw new ValidationError(`Invalid high at index ${i}`, 'candles.high');
    25→    }
    26→    if (typeof c.low !== 'number' || !isFinite(c.low) || c.low <= 0) {
    27→      throw new ValidationError(`Invalid low at index ${i}`, 'candles.low');
    28→    }
    29→    if (typeof c.close !== 'number' || !isFinite(c.close) || c.close <= 0) {
    30→      throw new ValidationError(`Invalid close at index ${i}`, 'candles.close');
    31→    }
    32→    if (c.high < c.low) {
    33→      throw new ValidationError(`High < Low at index ${i}`, 'candles.high');
    34→    }
    35→    if (c.high < c.open || c.high < c.close) {
    36→      throw new ValidationError(`High must be >= open and close at index ${i}`, 'candles.high');
    37→    }
    38→    if (c.low > c.open || c.low > c.close) {
    39→      throw new ValidationError(`Low must be <= open and close at index ${i}`, 'candles.low');
    40→    }
    41→
    42→    // Check ascending timestamps
    43→    if (i > 0) {
    44→      const prev = candles[i - 1]!;
    45→      if (c.timestamp <= prev.timestamp) {
    46→        throw new ValidationError(`Timestamps not ascending at index ${i}`, 'candles.timestamp');
    47→      }
    48→    }
    49→  }
    50→}
