    41→    const vwap = this.calculateVWAP(candles);
    42→    const ema20 = this.calculateEMA(candles, 20);
    43→    const ema50 = this.calculateEMA(candles, 50);
    44→    const ema200 = candles.length >= 200 ? this.calculateEMA(candles, 200) : ema50;
    45→    const rsi = this.calculateRSI(candles, 14);
    46→    const rsiDivergence = this.detectRSIDivergence(candles, 14);
    47→    const volumeProfile = this.calculateVolumeProfile(candles);
    48→    const cvdTrend = this.calculateCVDTrend(candles);
    49→
    50→    let priceVsVwap: 'ABOVE' | 'BELOW' | 'AT';
    51→    if (math.isGreater(lastPrice, math.add(vwap, 0.5))) priceVsVwap = 'ABOVE';
    52→    else if (math.isLess(lastPrice, math.sub(vwap, 0.5))) priceVsVwap = 'BELOW';
    53→    else priceVsVwap = 'AT';
    54→
    55→    let emaAlignment: 'BULLISH_STACK' | 'BEARISH_STACK' | 'MIXED';
    56→    if (ema20 > ema50 && ema50 > ema200) emaAlignment = 'BULLISH_STACK';
    57→    else if (ema20 < ema50 && ema50 < ema200) emaAlignment = 'BEARISH_STACK';
    58→    else emaAlignment = 'MIXED';
