    62→      priceVsVwap,
    63→      ema20,
    64→      ema50,
    65→      ema200,
    66→      emaAlignment,
    67→      rsi,
    68→      rsiDivergence,
    69→      volumeProfile,
    70→      cvdTrend,
    71→    };
