    74→  /**
    75→   * Session VWAP — anchored to the start of the candle array.
    76→   * VWAP = cumulative(TP * Volume) / cumulative(Volume)
    77→   * where TP = (H + L + C) / 3
    78→   */
    79→  calculateVWAP(candles: readonly Candle[]): number {
    80→    if (candles.length === 0) return 0;
    81→
    82→    let cumTPV = new Decimal(0);
    83→    let cumVol = new Decimal(0);
    84→
    85→    for (const c of candles) {
    86→      const tp = new Decimal(c.high).plus(c.low).plus(c.close).dividedBy(3);
    87→      cumTPV = cumTPV.plus(tp.times(c.volume));
    88→      cumVol = cumVol.plus(c.volume);
    89→    }
    90→
    91→    if (cumVol.isZero()) return candles[candles.length - 1]!.close;
    92→    return cumTPV.dividedBy(cumVol).toNumber();
    93→  }
    94→
    95→  /**
    96→   * Exponential Moving Average.
    97→   * EMA = price * k + prevEMA * (1-k)
    98→   * where k = 2 / (period + 1)
    99→   */
   100→  calculateEMA(candles: readonly Candle[], period: number): number {
   101→    if (candles.length === 0) return 0;
   102→    if (candles.length < period) return candles[candles.length - 1]!.close;
   103→
   104→    const k = 2 / (period + 1);
   105→
   106→    // SMA for the first `period` candles
   107→    let sum = 0;
   108→    for (let i = 0; i < period; i++) {
   109→      sum += candles[i]!.close;
   110→    }
   111→    let ema = sum / period;
   112→
   113→    // EMA for the rest
   114→    for (let i = period; i < candles.length; i++) {
   115→      ema = candles[i]!.close * k + ema * (1 - k);
   116→    }
   117→
   118→    return math.roundTo(ema, 4);
   119→  }
   120→
   121→  /**
   122→   * Relative Strength Index (0-100).
   123→   */
   124→  calculateRSI(candles: readonly Candle[], period: number = 14): number {
   125→    if (candles.length < period + 1) return 50;
   126→
   127→    let avgGain = 0;
   128→    let avgLoss = 0;
   129→
   130→    // Initial average
   131→    for (let i = 1; i <= period; i++) {
   132→      const change = candles[i]!.close - candles[i - 1]!.close;
   133→      if (change > 0) avgGain += change;
   134→      else avgLoss += Math.abs(change);
   135→    }
   136→    avgGain /= period;
   137→    avgLoss /= period;
   138→
   139→    // Smoothed RSI
   140→    for (let i = period + 1; i < candles.length; i++) {
   141→      const change = candles[i]!.close - candles[i - 1]!.close;
   142→      if (change > 0) {
   143→        avgGain = (avgGain * (period - 1) + change) / period;
   144→        avgLoss = (avgLoss * (period - 1)) / period;
   145→      } else {
   146→        avgGain = (avgGain * (period - 1)) / period;
   147→        avgLoss = (avgLoss * (period - 1) + Math.abs(change)) / period;
   148→      }
   149→    }
   150→
   151→    if (avgLoss === 0) return 100;
   152→    const rs = avgGain / avgLoss;
   153→    return math.roundTo(100 - 100 / (1 + rs), 2);
   154→  }
   155→
   156→  /**
   157→   * Detect RSI divergence with price.
   158→   * Bullish divergence: price makes lower low but RSI makes higher low.
   159→   * Bearish divergence: price makes higher high but RSI makes lower high.
   160→   */
   161→  detectRSIDivergence(
   162→    candles: readonly Candle[],
   163→    period: number = 14,
   164→  ): 'BULLISH_DIV' | 'BEARISH_DIV' | 'NONE' {
   165→    if (candles.length < period + 20) return 'NONE';
   166→
   167→    // Calculate RSI for last 20 candles
   168→    const rsiValues: number[] = [];
   169→    for (let end = candles.length - 20; end <= candles.length; end++) {
   170→      const slice = candles.slice(0, end);
   171→      if (slice.length >= period + 1) {
   172→        rsiValues.push(this.calculateRSI(slice, period));
   173→      }
   174→    }
   175→
   176→    if (rsiValues.length < 10) return 'NONE';
   177→
   178→    // Find swing lows in price and RSI
   179→    const priceLows = this.findLocalExtremes(
   180→      candles.slice(-20).map(c => c.low),
   181→      'LOW',
   182→    );
   183→    const rsiLows = this.findLocalExtremes(rsiValues, 'LOW');
   184→
   185→    // Check bullish divergence (price lower low, RSI higher low)
   186→    if (priceLows.length >= 2 && rsiLows.length >= 2) {
   187→      const priceMakesLL = priceLows[priceLows.length - 1]!.value < priceLows[priceLows.length - 2]!.value;
   188→      const rsiMakesHL = rsiLows[rsiLows.length - 1]!.value > rsiLows[rsiLows.length - 2]!.value;
   189→      if (priceMakesLL && rsiMakesHL) return 'BULLISH_DIV';
   190→    }
   191→
   192→    // Find swing highs in price and RSI
   193→    const priceHighs = this.findLocalExtremes(
   194→      candles.slice(-20).map(c => c.high),
   195→      'HIGH',
   196→    );
   197→    const rsiHighs = this.findLocalExtremes(rsiValues, 'HIGH');
   198→
   199→    // Check bearish divergence (price higher high, RSI lower high)
   200→    if (priceHighs.length >= 2 && rsiHighs.length >= 2) {
   201→      const priceMakesHH = priceHighs[priceHighs.length - 1]!.value > priceHighs[priceHighs.length - 2]!.value;
   202→      const rsiMakesLH = rsiHighs[rsiHighs.length - 1]!.value < rsiHighs[rsiHighs.length - 2]!.value;
   203→      if (priceMakesHH && rsiMakesLH) return 'BEARISH_DIV';
   204→    }
