   208→
   209→  /**
   210→   * Volume Profile — distribution of volume across price levels.
   211→   * Returns POC (Point of Control), Value Area High/Low, and HVN/LVN nodes.
   212→   */
   213→  calculateVolumeProfile(candles: readonly Candle[], bins: number = 30): VolumeProfile {
   214→    if (candles.length === 0) {
   215→      return { poc: 0, valueAreaHigh: 0, valueAreaLow: 0, highVolumeNodes: [], lowVolumeNodes: [] };
   216→    }
   217→
   218→    let minPrice = Infinity;
   219→    let maxPrice = -Infinity;
   220→    for (const c of candles) {
   221→      if (c.low < minPrice) minPrice = c.low;
   222→      if (c.high > maxPrice) maxPrice = c.high;
   223→    }
   224→
   225→    const range = maxPrice - minPrice;
   226→    if (range === 0) {
   227→      return { poc: minPrice, valueAreaHigh: minPrice, valueAreaLow: minPrice, highVolumeNodes: [], lowVolumeNodes: [] };
   228→    }
   229→
   230→    const binSize = range / bins;
   231→    const volumeByBin: number[] = new Array(bins).fill(0);
   232→
   233→    for (const c of candles) {
   234→      const tp = (c.high + c.low + c.close) / 3;
   235→      const binIndex = Math.min(bins - 1, Math.floor((tp - minPrice) / binSize));
   236→      volumeByBin[binIndex] = (volumeByBin[binIndex] ?? 0) + c.volume;
   237→    }
   238→
   239→    // POC: bin with highest volume
   240→    let maxVol = 0;
   241→    let pocBin = 0;
   242→    for (let i = 0; i < bins; i++) {
   243→      if (volumeByBin[i]! > maxVol) {
   244→        maxVol = volumeByBin[i]!;
   245→        pocBin = i;
   246→      }
   247→    }
   248→    const poc = math.roundTo(minPrice + (pocBin + 0.5) * binSize, 2);
   249→
   250→    // Value Area: 70% of total volume centered on POC
   251→    const totalVol = volumeByBin.reduce((a, b) => a + b, 0);
   252→    const targetVol = totalVol * 0.7;
   253→
   254→    let vaVol = volumeByBin[pocBin]!;
   255→    let vaLow = pocBin;
   256→    let vaHigh = pocBin;
   257→
   258→    while (vaVol < targetVol && (vaLow > 0 || vaHigh < bins - 1)) {
   259→      const canExpandLow = vaLow > 0;
   260→      const canExpandHigh = vaHigh < bins - 1;
   261→
   262→      if (canExpandLow && canExpandHigh) {
   263→        if (volumeByBin[vaLow - 1]! >= volumeByBin[vaHigh + 1]!) {
   264→          vaLow--;
   265→          vaVol += volumeByBin[vaLow]!;
   266→        } else {
   267→          vaHigh++;
   268→          vaVol += volumeByBin[vaHigh]!;
   269→        }
   270→      } else if (canExpandLow) {
   271→        vaLow--;
   272→        vaVol += volumeByBin[vaLow]!;
   273→      } else {
   274→        vaHigh++;
   275→        vaVol += volumeByBin[vaHigh]!;
   276→      }
   277→    }
   278→
   279→    const valueAreaLow = math.roundTo(minPrice + vaLow * binSize, 2);
   280→    const valueAreaHigh = math.roundTo(minPrice + (vaHigh + 1) * binSize, 2);
   281→
   282→    // HVN and LVN
   283→    const avgVol = totalVol / bins;
   284→    const highVolumeNodes: number[] = [];
   285→    const lowVolumeNodes: number[] = [];
   286→
   287→    for (let i = 0; i < bins; i++) {
   288→      const binPrice = math.roundTo(minPrice + (i + 0.5) * binSize, 2);
   289→      if (volumeByBin[i]! > avgVol * 1.5) {
   290→        highVolumeNodes.push(binPrice);
   291→      } else if (volumeByBin[i]! < avgVol * 0.5) {
   292→        lowVolumeNodes.push(binPrice);
   293→      }
   294→    }
   295→
   296→    return { poc, valueAreaHigh, valueAreaLow, highVolumeNodes, lowVolumeNodes };
   297→  }
   298→
   299→  /**
   300→   * Cumulative Volume Delta trend.
   301→   * CVD = cumulative(buyVolume - sellVolume)
   302→   * Buy volume estimated from candle: volume * (close - low) / (high - low)
   303→   */
   304→  calculateCVDTrend(candles: readonly Candle[], lookback: number = 20): 'BULLISH' | 'BEARISH' | 'NEUTRAL' {
   305→    if (candles.length < lookback) return 'NEUTRAL';
   306→
   307→    const recent = candles.slice(-lookback);
   308→    let cvd = 0;
   309→    const cvdValues: number[] = [];
   310→
   311→    for (const c of recent) {
   312→      const range = c.high - c.low;
   313→      if (range === 0) {
   314→        cvdValues.push(cvd);
   315→        continue;
   316→      }
   317→      const buyRatio = (c.close - c.low) / range;
   318→      const buyVol = c.volume * buyRatio;
   319→      const sellVol = c.volume * (1 - buyRatio);
   320→      cvd += buyVol - sellVol;
   321→      cvdValues.push(cvd);
   322→    }
   323→
   324→    // Check trend of CVD over the lookback
   325→    if (cvdValues.length < 5) return 'NEUTRAL';
   326→
   327→    const firstHalf = cvdValues.slice(0, Math.floor(cvdValues.length / 2));
   328→    const secondHalf = cvdValues.slice(Math.floor(cvdValues.length / 2));
   329→
   330→    const firstAvg = firstHalf.reduce((a, b) => a + b, 0) / firstHalf.length;
   331→    const secondAvg = secondHalf.reduce((a, b) => a + b, 0) / secondHalf.length;
   332→
   333→    const diff = secondAvg - firstAvg;
   334→    const threshold = Math.abs(firstAvg) * 0.1 || 100;
   335→
   336→    if (diff > threshold) return 'BULLISH';
   337→    if (diff < -threshold) return 'BEARISH';
   338→    return 'NEUTRAL';
   339→  }
   340→
   341→  /** Find local extremes (highs or lows) in a numeric array */
   342→  private findLocalExtremes(
   343→    values: number[],
   344→    type: 'HIGH' | 'LOW',
   345→    lookback: number = 3,
   346→  ): { index: number; value: number }[] {
   347→    const extremes: { index: number; value: number }[] = [];
   348→    if (values.length < lookback * 2 + 1) return extremes;
   349→
   350→    for (let i = lookback; i < values.length - lookback; i++) {
   351→      let isExtreme = true;
   352→      for (let j = i - lookback; j <= i + lookback; j++) {
   353→        if (j === i) continue;
   354→        if (type === 'HIGH' && values[j]! >= values[i]!) { isExtreme = false; break; }
   355→        if (type === 'LOW' && values[j]! <= values[i]!) { isExtreme = false; break; }
   356→      }
   357→      if (isExtreme) {
   358→        extremes.push({ index: i, value: values[i]! });
   359→      }
   360→    }
   361→
   362→    return extremes;
   363→  }
   364→}
