   219→   */
   220→  calculateDealingRange(swings: readonly SwingPoint[]): DealingRange | null {
   221→    const highs = swings.filter(s => s.type === 'HIGH');
   222→    const lows = swings.filter(s => s.type === 'LOW');
   223→
   224→    if (highs.length === 0 || lows.length === 0) return null;
   225→
   226→    // Use most recent swing high and low (not absolute extremes)
   227→    const recentHigh = highs[highs.length - 1]!;
   228→    const recentLow = lows[lows.length - 1]!;
   229→
   230→    // If the most recent high is below the most recent low,
   231→    // find the nearest high above and low below current context
   232→    let high: number;
   233→    let low: number;
   234→
   235→    if (math.isGreater(recentHigh.price, recentLow.price)) {
   236→      high = recentHigh.price;
   237→      low = recentLow.price;
   238→    } else {
   239→      // Fallback: find the highest recent high and lowest recent low
   240→      // from the last 3 swings on each side
   241→      const lastHighs = highs.slice(-3);
   242→      const lastLows = lows.slice(-3);
   243→      high = lastHighs.reduce((a, b) => math.isGreater(a.price, b.price) ? a : b).price;
   244→      low = lastLows.reduce((a, b) => math.isLess(a.price, b.price) ? a : b).price;
   245→    }
   246→
   247→    const eq = math.midpoint(high, low);
   248→
   249→    // Premium zone: upper half (above equilibrium)
   250→    // Discount zone: lower half (below equilibrium)
   251→    const premium = { upper: high, lower: eq };
   252→    const discount = { upper: eq, lower: low };
   253→
   254→    // OTE zone: 62% - 79% retracement
   255→    const oteUpper = math.fibLevel(high, low, OTE_LEVELS.lower); // 62% retrace
   256→    const oteLower = math.fibLevel(high, low, OTE_LEVELS.upper); // 79% retrace
   257→
   258→    return {
   259→      high,
   260→      low,
   261→      equilibrium: eq,
   262→      premium,
   263→      discount,
   264→      ote: { upper: oteUpper, lower: oteLower },
   265→    };
   266→  }
   267→
   268→  /**
   269→   * Determine which zone a price falls in relative to the dealing range.
   270→   */
   271→  getZone(price: number, range: DealingRange): Zone {
   272→    if (math.isGte(price, range.premium.lower)) return 'PREMIUM';
   273→    if (math.isLte(price, range.discount.upper)) return 'DISCOUNT';
   274→    return 'EQUILIBRIUM';
   275→  }
   276→
   277→  /**
   278→   * Check if price is in the Optimal Trade Entry zone (62-79% fib retracement).
   279→   */
   280→  isInOTE(price: number, range: DealingRange): boolean {
   281→    return math.isLte(price, range.ote.upper) && math.isGte(price, range.ote.lower);
   282→  }
   283→
   284→  /**
   285→   * Validate zone alignment for direction.
   286→   * Longs should be in discount, shorts in premium.
   287→   */
   288→  isZoneValid(zone: Zone, direction: Direction): boolean {
   289→    if (direction === 'LONG') return zone === 'DISCOUNT';
   290→    if (direction === 'SHORT') return zone === 'PREMIUM';
   291→    return false;
   292→  }
   293→
   294→  /** Calculate swing strength based on surrounding price action (1-5) */
   295→  private calculateStrength(
   296→    candles: readonly Candle[],
   297→    index: number,
   298→    type: 'HIGH' | 'LOW',
   299→  ): number {
   300→    let strength = 1;
   301→    const candle = candles[index]!;
   302→    const extendedLookback = Math.min(this.lookback * 2, index, candles.length - index - 1);
   303→
   304→    // Higher strength if it dominates a wider range
   305→    let dominates = 0;
   306→    for (let j = 1; j <= extendedLookback; j++) {
   307→      const left = candles[index - j];
   308→      const right = candles[index + j];
   309→      if (!left || !right) break;
   310→
   311→      if (type === 'HIGH') {
   312→        if (candle.high > left.high && candle.high > right.high) dominates++;
   313→      } else {
   314→        if (candle.low < left.low && candle.low < right.low) dominates++;
   315→      }
   316→    }
   317→
   318→    strength = Math.min(5, Math.max(1, Math.ceil(dominates / 2)));
   319→    return strength;
   320→  }
   321→}
   322→

