     1→import type {
     2→  Candle,
     3→  SwingPoint,
     4→  LiquidityLevel,
     5→  LiquiditySweep,
     6→  LiquidityType,
     7→  LiquidityRank,
     8→} from '../core/types.js';
     9→import { LIQUIDITY_WEIGHTS } from '../core/constants.js';
    10→import * as math from '../utils/math.js';
    11→import * as time from '../utils/time.js';
    12→
    13→/**
    14→ * LiquidityAnalyzer — Maps and tracks liquidity levels, detects sweeps.
    15→ */
    16→export class LiquidityAnalyzer {
    17→  private readonly eqTolerance: number;
    18→
    19→  /**
    20→   * @param eqTolerance Tolerance for detecting equal highs/lows (absolute price distance)
    21→   */
    22→  constructor(eqTolerance: number = 0.5) {
    23→    this.eqTolerance = eqTolerance;
    24→  }
    25→
    26→  /**
    27→   * Map all external liquidity levels from historical data.
    28→   * Sources: PDH/PDL, PWH/PWL, Asian range, EQH/EQL, BSL/SSL from swing points.
    29→   */
    30→  mapAllLevels(
    31→    candles: readonly Candle[],
    32→    swings: readonly SwingPoint[],
    33→    referenceTimestamp: number,
    34→  ): LiquidityLevel[] {
    35→    const levels: LiquidityLevel[] = [];
    36→
    37→    // Previous Day High/Low
    38→    const pdRange = time.getPreviousDayRange(candles, referenceTimestamp);
    39→    if (pdRange) {
    40→      levels.push(this.createLevel(pdRange.high, 'PDH'));
    41→      levels.push(this.createLevel(pdRange.low, 'PDL'));
    42→    }
    43→
    44→    // Previous Week High/Low
    45→    const pwRange = time.getPreviousWeekRange(candles, referenceTimestamp);
    46→    if (pwRange) {
    47→      levels.push(this.createLevel(pwRange.high, 'PWH'));
    48→      levels.push(this.createLevel(pwRange.low, 'PWL'));
    49→    }
    50→
    51→    // Asian Session Range
    52→    const asianRange = time.getAsianSessionRange(candles, referenceTimestamp);
    53→    if (asianRange) {
    54→      levels.push(this.createLevel(asianRange.high, 'ASIAN_HIGH'));
    55→      levels.push(this.createLevel(asianRange.low, 'ASIAN_LOW'));
    56→    }
    57→
    58→    // Equal Highs/Lows
    59→    const eqLevels = this.detectEqualHighsLows(swings);
    60→    levels.push(...eqLevels);
    61→
    62→    // Buy/Sell Side Liquidity from swing points
    63→    const bslSsl = this.mapSwingLiquidity(swings);
    64→    levels.push(...bslSsl);
    65→
    66→    return levels;
    67→  }
    68→
    69→  /**
    70→   * Detect equal highs and equal lows from swing points.
    71→   * Two or more swing highs within tolerance = EQH (resting buy stops above).
    72→   * Two or more swing lows within tolerance = EQL (resting sell stops below).
    73→   */
    74→  detectEqualHighsLows(swings: readonly SwingPoint[]): LiquidityLevel[] {
    75→    const levels: LiquidityLevel[] = [];
    76→    const highs = swings.filter(s => s.type === 'HIGH');
    77→    const lows = swings.filter(s => s.type === 'LOW');
    78→
    79→    // Detect equal highs
    80→    const eqHighGroups = this.findEqualGroups(highs);
    81→    for (const group of eqHighGroups) {
    82→      const avgPrice = group.reduce((sum, s) => sum + s.price, 0) / group.length;
    83→      levels.push(this.createLevel(avgPrice, 'EQH'));
    84→    }
    85→
    86→    // Detect equal lows
    87→    const eqLowGroups = this.findEqualGroups(lows);
    88→    for (const group of eqLowGroups) {
    89→      const avgPrice = group.reduce((sum, s) => sum + s.price, 0) / group.length;
    90→      levels.push(this.createLevel(avgPrice, 'EQL'));
    91→    }
    92→
    93→    return levels;
    94→  }
    95→
    96→  /**
    97→   * Detect liquidity sweeps.
    98→   * A sweep occurs when price wicks beyond a level but closes back inside.
    99→   */
   100→  detectSweeps(
   101→    candles: readonly Candle[],
   102→    levels: readonly LiquidityLevel[],
   103→    lookback: number = 20,
   104→  ): LiquiditySweep[] {
   105→    const sweeps: LiquiditySweep[] = [];
   106→    const startIdx = Math.max(0, candles.length - lookback);
   107→
   108→    for (const level of levels) {
   109→      if (level.swept) continue;
   110→
   111→      const isBuySide = this.isBuySideLiquidity(level.type);
   112→
   113→      for (let i = startIdx; i < candles.length; i++) {
   114→        const candle = candles[i]!;
   115→
   116→        if (isBuySide) {
   117→          // BSL sweep: wick above level, close below
   118→          if (
   119→            math.isGreater(candle.high, level.price) &&
   120→            math.isLte(candle.close, level.price)
   121→          ) {
   122→            const reint = this.checkReintegration(candles, i, level, true);
   123→            sweeps.push({
   124→              level: { ...level, swept: true, sweepTimestamp: candle.timestamp },
   125→              sweepCandle: candle,
   126→              sweepIndex: i,
   127→              penetrationDepth: math.sub(candle.high, level.price),
   128→              reintegrated: reint.reintegrated,
   129→              reintegrationSpeed: reint.speed,
   130→            });
   131→            break;
   132→          }
   133→        } else {
   134→          // SSL sweep: wick below level, close above
   135→          if (
   136→            math.isLess(candle.low, level.price) &&
   137→            math.isGte(candle.close, level.price)
   138→          ) {
   139→            const reint = this.checkReintegration(candles, i, level, false);
   140→            sweeps.push({
   141→              level: { ...level, swept: true, sweepTimestamp: candle.timestamp },
   142→              sweepCandle: candle,
   143→              sweepIndex: i,
   144→              penetrationDepth: math.sub(level.price, candle.low),
   145→              reintegrated: reint.reintegrated,
   146→              reintegrationSpeed: reint.speed,
   147→            });
   148→            break;
   149→          }
   150→        }
   151→      }
   152→    }
   153→
   154→    return sweeps;
   155→  }
   156→
   157→  /** Create a LiquidityLevel with rank and weight from constants */
   158→  private createLevel(price: number, type: LiquidityType): LiquidityLevel {
   159→    const config = LIQUIDITY_WEIGHTS[type];
   160→    return {
   161→      price,
   162→      type,
   163→      rank: (config?.rank ?? 'C') as LiquidityRank,
   164→      weight: config?.weight ?? 50,
   165→      swept: false,
   166→    };
   167→  }
   168→
   169→  /** Map swing points to BSL/SSL liquidity */
   170→  private mapSwingLiquidity(swings: readonly SwingPoint[]): LiquidityLevel[] {
   171→    const levels: LiquidityLevel[] = [];
   172→    for (const swing of swings) {
   173→      if (swing.type === 'HIGH') {
   174→        levels.push(this.createLevel(swing.price, 'BSL'));
   175→      } else {
   176→        levels.push(this.createLevel(swing.price, 'SSL'));
   177→      }
   178→    }
   179→    return levels;
   180→  }
   181→
   182→  /** Find groups of swing points at approximately equal prices */
   183→  private findEqualGroups(swings: readonly SwingPoint[]): SwingPoint[][] {
   184→    const groups: SwingPoint[][] = [];
   185→    const used = new Set<number>();
   186→
   187→    for (let i = 0; i < swings.length; i++) {
   188→      if (used.has(i)) continue;
   189→      const group = [swings[i]!];
   190→      used.add(i);
   191→
   192→      for (let j = i + 1; j < swings.length; j++) {
   193→        if (used.has(j)) continue;
   194→        if (math.isApproxEqual(swings[i]!.price, swings[j]!.price, this.eqTolerance)) {
   195→          group.push(swings[j]!);
   196→          used.add(j);
   197→        }
   198→      }
   199→
   200→      if (group.length >= 2) {
   201→        groups.push(group);
   202→      }
   203→    }
   204→
   205→    return groups;
   206→  }
   207→
   208→  /** Check if a liquidity type is buy-side (above price) */
   209→  private isBuySideLiquidity(type: LiquidityType): boolean {
   210→    return ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(type);
   211→  }
   212→
   213→  /** Check reintegration after a sweep */
   214→  private checkReintegration(
   215→    candles: readonly Candle[],
   216→    sweepIndex: number,
   217→    level: LiquidityLevel,
   218→    isBuySide: boolean,
   219→    maxCandles: number = 10,
   220→  ): { reintegrated: boolean; speed: number } {
   221→    let speed = 0;
   222→
   223→    for (let i = sweepIndex + 1; i < Math.min(candles.length, sweepIndex + maxCandles + 1); i++) {
   224→      speed++;
   225→      const c = candles[i]!;
   226→      if (isBuySide) {
   227→        // After BSL sweep, price closing back well below = reintegrated
   228→        if (math.isLess(c.close, level.price)) {
   229→          return { reintegrated: true, speed };
   230→        }
   231→      } else {
   232→        // After SSL sweep, price closing back well above = reintegrated
   233→        if (math.isGreater(c.close, level.price)) {
   234→          return { reintegrated: true, speed };
   235→        }
   236→      }
   237→    }
   238→
   239→    return { reintegrated: false, speed };
   240→  }
   241→}
