     2→  Candle,
     3→  SwingPoint,
     4→  FairValueGap,
     5→  OrderBlock,
     6→  Direction,
     7→} from '../core/types.js';
     8→import * as math from '../utils/math.js';
     9→
    10→export interface BreakerBlock {
    11→  readonly high: number;
    12→  readonly low: number;
    13→  readonly direction: Direction;
    14→  readonly timestamp: number;
    15→  readonly index: number;
    16→  readonly originalOBDirection: Direction;
    17→}
    18→
    19→/**
    20→ * EntryDetector — FVG, Order Block, and Breaker Block detection
    21→ * with fill/mitigation tracking and deduplication.
    22→ */
    23→export class EntryDetector {
    24→  private readonly minFVGSize: number;
    25→
    26→  constructor(minFVGSize: number) {
    27→    this.minFVGSize = minFVGSize;
    28→  }
    29→
    30→  /**
    31→   * Detect Fair Value Gaps in candle data.
    32→   * Bullish FVG: candle[i-1].high < candle[i+1].low (gap up)
    33→   * Bearish FVG: candle[i-1].low > candle[i+1].high (gap down)
    34→   */
    35→  detectFVG(candles: readonly Candle[]): FairValueGap[] {
    36→    const fvgs: FairValueGap[] = [];
    37→    if (candles.length < 3) return fvgs;
    38→
    39→    for (let i = 1; i < candles.length - 1; i++) {
    40→      const prev = candles[i - 1]!;
    41→      const curr = candles[i]!;
    42→      const next = candles[i + 1]!;
    43→
    44→      // Bullish FVG: gap between prev.high and next.low
    45→      if (math.isLess(prev.high, next.low)) {
    46→        const low = prev.high;
    47→        const high = next.low;
    48→        const size = math.sub(high, low);
    49→
    50→        if (math.isGte(size, this.minFVGSize)) {
    51→          fvgs.push({
    52→            high,
    53→            low,
    54→            midpoint: math.midpoint(high, low),
    55→            size,
    56→            direction: 'LONG',
    57→            timestamp: curr.timestamp,
    58→            index: i,
    59→            fillPercent: 0,
    60→            isValid: true,
    61→          });
    62→        }
    63→      }
    64→
    65→      // Bearish FVG: gap between next.high and prev.low
    66→      if (math.isGreater(prev.low, next.high)) {
    67→        const high = prev.low;
    68→        const low = next.high;
    69→        const size = math.sub(high, low);
    70→
    71→        if (math.isGte(size, this.minFVGSize)) {
    72→          fvgs.push({
    73→            high,
    74→            low,
    75→            midpoint: math.midpoint(high, low),
    76→            size,
    77→            direction: 'SHORT',
    78→            timestamp: curr.timestamp,
    79→            index: i,
    80→            fillPercent: 0,
    81→            isValid: true,
    82→          });
    83→        }
    84→      }
    85→    }
    86→
    87→    return fvgs;
    88→  }
    89→
    90→  /**
    91→   * Detect Order Blocks with deduplication.
    92→   * Bullish OB: last bearish candle before a bullish displacement.
    93→   * Bearish OB: last bullish candle before a bearish displacement.
    94→   *
    95→   * Deduplication: if two OBs share the same candle index, keep only the one
    96→   * with the larger displacement.
    97→   */
    98→  detectOrderBlocks(
    99→    candles: readonly Candle[],
   100→    _swings: readonly SwingPoint[],
   101→  ): OrderBlock[] {
   102→    const rawOBs: (OrderBlock & { displacementSize: number })[] = [];
   103→    if (candles.length < 3) return [];
   104→
   105→    for (let i = 2; i < candles.length; i++) {
   106→      const curr = candles[i]!;
   107→      const prev = candles[i - 1]!;
   108→
   109→      // Bullish displacement: strong close above previous high
   110→      const bullishBody = math.sub(curr.close, curr.open);
   111→      const currRange = math.sub(curr.high, curr.low);
   112→      const isBullishDisplacement =
   113→        math.isGreater(curr.close, curr.open) &&
   114→        math.isGreater(curr.close, prev.high) &&
   115→        math.isGreater(bullishBody, math.mul(currRange, 0.5));
   116→
   117→      if (isBullishDisplacement) {
   118→        for (let j = i - 1; j >= Math.max(0, i - 5); j--) {
   119→          const ob = candles[j]!;
   120→          if (math.isLess(ob.close, ob.open)) {
   121→            const confirmed = math.isGreater(curr.close, ob.high);
   122→            rawOBs.push({
   123→              high: ob.high,
   124→              low: ob.low,
   125→              open: ob.open,
   126→              close: ob.close,
   127→              timestamp: ob.timestamp,
   128→              index: j,
   129→              direction: 'LONG',
   130→              confirmed,
   131→              mitigated: false,
   132→              displacementSize: bullishBody,
   133→            });
   134→            break;
   135→          }
   136→        }
   137→      }
   138→
   139→      // Bearish displacement: strong close below previous low
   140→      const bearishBody = math.sub(curr.open, curr.close);
   141→      const isBearishDisplacement =
   142→        math.isLess(curr.close, curr.open) &&
   143→        math.isLess(curr.close, prev.low) &&
   144→        math.isGreater(bearishBody, math.mul(currRange, 0.5));
   145→
   146→      if (isBearishDisplacement) {
   147→        for (let j = i - 1; j >= Math.max(0, i - 5); j--) {
   148→          const ob = candles[j]!;
   149→          if (math.isGreater(ob.close, ob.open)) {
   150→            const confirmed = math.isLess(curr.close, ob.low);
   151→            rawOBs.push({
   152→              high: ob.high,
   153→              low: ob.low,
   154→              open: ob.open,
   155→              close: ob.close,
   156→              timestamp: ob.timestamp,
   157→              index: j,
   158→              direction: 'SHORT',
   159→              confirmed,
   160→              mitigated: false,
   161→              displacementSize: bearishBody,
   162→            });
   163→            break;
   164→          }
   165→        }
   166→      }
   167→    }
   168→
   169→    // Deduplicate: for OBs at the same index+direction, keep the one with the larger displacement
   170→    return this.deduplicateOBs(rawOBs);
   171→  }
   172→
   173→  /**
   174→   * Detect Breaker Blocks.
   175→   * A Breaker Block is a failed Order Block — an OB that was mitigated
   176→   * and then price reversed through it. It becomes a new support/resistance.
   177→   *
   178→   * Bullish Breaker: a bearish OB that was broken and now acts as support.
   179→   * Bearish Breaker: a bullish OB that was broken and now acts as resistance.
   180→   */
   181→  detectBreakerBlocks(
   182→    candles: readonly Candle[],
   183→    orderBlocks: readonly OrderBlock[],
   184→  ): BreakerBlock[] {
   185→    const breakers: BreakerBlock[] = [];
   186→
   187→    for (const ob of orderBlocks) {
   188→      if (!ob.mitigated) continue;
   189→
   190→      // Find the candle that broke the OB
   191→      for (let i = ob.index + 1; i < candles.length; i++) {
   192→        const c = candles[i]!;
   193→
   194→        if (ob.direction === 'LONG') {
   195→          // Bullish OB failed: price broke below OB low, then reversed above
   196→          if (math.isLess(c.close, ob.low)) {
   197→            // Now check if price reversed back above OB high
   198→            for (let k = i + 1; k < candles.length; k++) {
   199→              if (math.isGreater(candles[k]!.close, ob.high)) {
   200→                breakers.push({
   201→                  high: ob.high,
   202→                  low: ob.low,
   203→                  direction: 'LONG', // Now acts as bullish support (breaker)
   204→                  timestamp: candles[k]!.timestamp,
   205→                  index: k,
   206→                  originalOBDirection: 'LONG',
   207→                });
   208→                break;
   209→              }
   210→            }
   211→            break;
   212→          }
   213→        } else {
   214→          // Bearish OB failed: price broke above OB high, then reversed below
   215→          if (math.isGreater(c.close, ob.high)) {
   216→            for (let k = i + 1; k < candles.length; k++) {
   217→              if (math.isLess(candles[k]!.close, ob.low)) {
   218→                breakers.push({
   219→                  high: ob.high,
   220→                  low: ob.low,
   221→                  direction: 'SHORT', // Now acts as bearish resistance (breaker)
   222→                  timestamp: candles[k]!.timestamp,
   223→                  index: k,
   224→                  originalOBDirection: 'SHORT',
   225→                });
   226→                break;
   227→              }
   228→            }
   229→            break;
   230→          }
   231→        }
   232→      }
   233→    }
   234→
   235→    return breakers;
   236→  }
   237→
   238→  /**
   239→   * Update FVG fill status based on subsequent price action.
   240→   */
   241→  updateFVGFillStatus(
   242→    fvgs: readonly FairValueGap[],
   243→    candles: readonly Candle[],
   244→  ): FairValueGap[] {
   245→    return fvgs.map(fvg => {
   246→      let maxFill = 0;
   247→
   248→      for (let i = fvg.index + 2; i < candles.length; i++) {
   249→        const c = candles[i]!;
   250→
   251→        if (fvg.direction === 'LONG') {
   252→          if (math.isLte(c.low, fvg.high)) {
   253→            const filled = math.sub(fvg.high, math.max(c.low, fvg.low));
   254→            const pct = math.mul(math.div(filled, fvg.size), 100);
   255→            maxFill = Math.max(maxFill, Math.min(100, pct));
   256→          }
   257→        } else {
   258→          if (math.isGte(c.high, fvg.low)) {
   259→            const filled = math.sub(math.min(c.high, fvg.high), fvg.low);
   260→            const pct = math.mul(math.div(filled, fvg.size), 100);
   261→            maxFill = Math.max(maxFill, Math.min(100, pct));
   262→          }
   263→        }
   264→      }
   265→
   266→      return {
   267→        ...fvg,
   268→        fillPercent: maxFill,
   269→        isValid: fvg.size >= this.minFVGSize && maxFill < 50,
   270→      };
   271→    });
   272→  }
   273→
   274→  /**
   275→   * Update Order Block mitigation status.
   276→   */
   277→  updateOBMitigation(
   278→    obs: readonly OrderBlock[],
   279→    candles: readonly Candle[],
   280→  ): OrderBlock[] {
   281→    return obs.map(ob => {
   282→      const bodyMid = math.midpoint(ob.open, ob.close);
   283→
   284→      for (let i = ob.index + 1; i < candles.length; i++) {
   285→        const c = candles[i]!;
   286→        if (ob.direction === 'LONG') {
   287→          if (math.isLess(c.low, bodyMid)) {
   288→            return { ...ob, mitigated: true };
   289→          }
   290→        } else {
   291→          if (math.isGreater(c.high, bodyMid)) {
   292→            return { ...ob, mitigated: true };
   293→          }
   294→        }
   295→      }
   296→
   297→      return ob;
   298→    });
   299→  }
   300→
   301→  /**
   302→   * Check if a FVG overlaps with an Order Block.
   303→   */
   304→  checkFVGOBOverlap(fvg: FairValueGap, ob: OrderBlock): boolean {
   305→    if (fvg.direction !== ob.direction) return false;
   306→    return math.isLte(fvg.low, ob.high) && math.isGte(fvg.high, ob.low);
   307→  }
   308→
   309→  /**
   310→   * Find the best entry zone from available FVGs and OBs.
   311→   * Prioritizes: FVG+OB overlap > valid FVG > confirmed OB
   312→   */
   313→  findBestEntry(
   314→    fvgs: readonly FairValueGap[],
   315→    obs: readonly OrderBlock[],
   316→    direction: Direction,
   317→  ): { fvg: FairValueGap | null; ob: OrderBlock | null; hasOverlap: boolean } {
   318→    const validFVGs = fvgs.filter(f => f.direction === direction && f.isValid);
   319→    const validOBs = obs.filter(o => o.direction === direction && o.confirmed && !o.mitigated);
   320→
   321→    // Check for overlap
   322→    for (const fvg of validFVGs) {
   323→      for (const ob of validOBs) {
   324→        if (this.checkFVGOBOverlap(fvg, ob)) {
   325→          return { fvg, ob, hasOverlap: true };
   326→        }
   327→      }
   328→    }
   329→
   330→    // Return best individual
   331→    const bestFVG = validFVGs[validFVGs.length - 1] ?? null;
   332→    const bestOB = validOBs[validOBs.length - 1] ?? null;
   333→
   334→    return { fvg: bestFVG, ob: bestOB, hasOverlap: false };
   335→  }
   336→
   337→  /** Deduplicate OBs: if two share the same index and direction, keep the one with larger displacement */
   338→  private deduplicateOBs(obs: (OrderBlock & { displacementSize: number })[]): OrderBlock[] {
   339→    const byKey = new Map<string, OrderBlock & { displacementSize: number }>();
   340→
   341→    for (const ob of obs) {
   342→      const key = `${ob.index}-${ob.direction}`;
   343→      const existing = byKey.get(key);
   344→      if (!existing || ob.displacementSize > existing.displacementSize) {
   345→        byKey.set(key, ob);
   346→      }
   347→    }
   348→
   349→    // Strip the extra displacementSize field
   350→    return Array.from(byKey.values()).map(({ displacementSize: _, ...ob }) => ob);
   351→  }
   352→}
