     1→import type { KillZoneName } from '../core/types.js';
     2→import { KILL_ZONES } from '../core/constants.js';
     3→import * as time from '../utils/time.js';
     4→
     5→export interface KillZoneInfo {
     6→  readonly name: KillZoneName;
     7→  readonly quality: number;
     8→  readonly allowed: boolean;
     9→  readonly minutesRemaining: number;
    10→}
    11→
    12→/**
    13→ * KillZoneManager — Time-based trade filtering.
    14→ * All times are in NY timezone.
    15→ */
    16→export class KillZoneManager {
    17→  /**
    18→   * Get the current kill zone info for a timestamp.
    19→   * Returns null if outside all kill zones.
    20→   */
    21→  getCurrentKillZone(timestamp: number): KillZoneInfo | null {
    22→    const kz = time.getCurrentKillZone(timestamp);
    23→    if (!kz) return null;
    24→
    25→    const hour = time.getNYHourDecimal(timestamp);
    26→    let minutesRemaining: number;
    27→
    28→    if (kz.config.start > kz.config.end) {
    29→      // Crosses midnight
    30→      if (hour >= kz.config.start) {
    31→        minutesRemaining = (24 - hour + kz.config.end) * 60;
    32→      } else {
    33→        minutesRemaining = (kz.config.end - hour) * 60;
    34→      }
    35→    } else {
    36→      minutesRemaining = (kz.config.end - hour) * 60;
    37→    }
    38→
    39→    return {
    40→      name: kz.name,
    41→      quality: kz.quality,
    42→      allowed: kz.allowed,
    43→      minutesRemaining: Math.max(0, Math.round(minutesRemaining)),
    44→    };
    45→  }
    46→
    47→  /**
    48→   * Check if the current time is in an optimal trading window.
    49→   * Optimal = NY Open or London Open (quality >= 3).
    50→   */
    51→  isOptimalTime(timestamp: number): boolean {
    52→    const kz = this.getCurrentKillZone(timestamp);
    53→    if (!kz) return false;
    54→    return kz.quality >= 3;
    55→  }
    56→
    57→  /**
    58→   * Get the next upcoming kill zone.
    59→   */
    60→  getNextKillZone(timestamp: number): { name: KillZoneName; startsIn: number } | null {
    61→    const hour = time.getNYHourDecimal(timestamp);
    62→
    63→    let bestKz: { name: KillZoneName; startsIn: number } | null = null;
    64→    let minWait = Infinity;
    65→
    66→    for (const kz of KILL_ZONES) {
    67→      let waitHours: number;
    68→
    69→      if (kz.start > hour) {
    70→        waitHours = kz.start - hour;
    71→      } else {
    72→        waitHours = 24 - hour + kz.start;
    73→      }
    74→
    75→      const waitMinutes = waitHours * 60;
    76→
    77→      // Skip if we're currently in this zone
    78→      if (waitMinutes < 1) continue;
    79→
    80→      if (waitMinutes < minWait) {
    81→        minWait = waitMinutes;
    82→        bestKz = { name: kz.name, startsIn: Math.round(waitMinutes) };
    83→      }
    84→    }
    85→
    86→    return bestKz;
    87→  }
    88→
    89→  /**
    90→   * Check if the timestamp falls in a no-trade zone (lunch, after hours).
    91→   */
    92→  isNoTradeZone(timestamp: number): boolean {
    93→    return time.isNoTradeZone(timestamp);
    94→  }
    95→
    96→  /**
    97→   * Check if trading is allowed at this time.
    98→   * Blocked during: weekends, no-trade zones, outside kill zones.
    99→   */
   100→  isTradingAllowed(timestamp: number): {
   101→    allowed: boolean;
   102→    reason: string;
   103→  } {
   104→    if (time.isWeekend(timestamp)) {
   105→      return { allowed: false, reason: 'Weekend — markets closed' };
   106→    }
   107→
   108→    if (this.isNoTradeZone(timestamp)) {
   109→      return { allowed: false, reason: 'No-trade zone (lunch or after hours)' };
   110→    }
   111→
   112→    const kz = this.getCurrentKillZone(timestamp);
   113→    if (!kz) {
   114→      return { allowed: false, reason: 'Outside kill zone' };
   115→    }
   116→
   117→    if (!kz.allowed) {
   118→      return { allowed: false, reason: `Kill zone ${kz.name} not allowed for trading` };
   119→    }
   120→
   121→    return { allowed: true, reason: `In ${kz.name} kill zone` };
   122→  }
   123→}
