    14→} from '../core/types.js';
    15→import type { IndicatorSnapshot } from '../analysis/Indicators.js';
    16→import {
    17→  IMMUTABLE_RULES,
    18→  SCORE_GRADES,
    19→  SCORE_MAXIMUMS,
    20→} from '../core/constants.js';
    21→import * as math from '../utils/math.js';
    22→
    23→export interface ScoreInput {
    24→  readonly htfTrend: Trend;
    25→  readonly htfAligned: boolean;
    26→  readonly zone: Zone;
    27→  readonly zoneValid: boolean;
    28→  readonly direction: Direction;
    29→  readonly dealingRange: DealingRange | null;
    30→  readonly currentPrice: number;
    31→  readonly sweep: LiquiditySweep | null;
    32→  readonly amd: AMDPattern;
    33→  readonly fvg: FairValueGap | null;
    34→  readonly ob: OrderBlock | null;
    35→  readonly fvgObOverlap: boolean;
    36→  readonly killZone: KillZoneName;
    37→  readonly killZoneQuality: number;
    38→  readonly macro: MacroContext;
    39→  readonly isInOTE: boolean;
    40→  readonly indicators?: IndicatorSnapshot | null;
    41→}
    42→
    43→/**
    44→ * SetupScorer — 100-point scoring system for trade setup quality.
    45→ *
    46→ * Categories:
    47→ *   A. Structure Alignment: 30 pts max (includes EMA + VWAP confluence)
    48→ *   B. Judas Swing Quality: 25 pts max (includes CVD confirmation)
    49→ *   C. Entry Quality: 25 pts max (includes volume profile confluence)
    50→ *   D. Macro Context: 20 pts max (includes RSI divergence)
    51→ */
    52→export class SetupScorer {
    53→  calculateScore(input: ScoreInput): SetupScore {
    54→    const disqualifications = this.checkDisqualifications(input);
    55→
    56→    if (disqualifications.length > 0) {
    57→      return {
    58→        structureAlignment: 0,
    59→        judasSwingQuality: 0,
    60→        entryQuality: 0,
    61→        macroContext: 0,
    62→        total: 0,
    63→        grade: 'DISQUALIFIED',
    64→        sizing: 0,
    65→        tradeable: false,
    66→      };
    67→    }
    68→
    69→    const structureAlignment = this.scoreStructure(input);
    70→    const judasSwingQuality = this.scoreJudasSwing(input);
    71→    const entryQuality = this.scoreEntry(input);
    72→    const macroContext = this.scoreMacro(input);
    73→
    74→    const total = structureAlignment + judasSwingQuality + entryQuality + macroContext;
    75→    const grade = this.assignGrade(total);
    76→    const sizing = this.getSizing(grade);
    77→    const tradeable = total >= IMMUTABLE_RULES.MIN_SCORE_THRESHOLD && grade !== 'DISQUALIFIED';
    78→
    79→    return {
    80→      structureAlignment,
    81→      judasSwingQuality,
    82→      entryQuality,
    83→      macroContext,
    84→      total,
    85→      grade,
    86→      sizing,
    87→      tradeable,
    88→    };
    89→  }
    90→
    91→  checkDisqualifications(input: ScoreInput): string[] {
    92→    const dqs: string[] = [];
    93→
    94→    if (IMMUTABLE_RULES.HTF_ALIGNMENT_REQUIRED && !input.htfAligned) {
    95→      dqs.push('HTF bias not aligned');
    96→    }
    97→
    98→    if (IMMUTABLE_RULES.LONG_ONLY_IN_DISCOUNT && input.direction === 'LONG' && input.zone !== 'DISCOUNT') {
    99→      dqs.push('Long entry not in discount zone');
   100→    }
   101→
   102→    if (IMMUTABLE_RULES.SHORT_ONLY_IN_PREMIUM && input.direction === 'SHORT' && input.zone !== 'PREMIUM') {
   103→      dqs.push('Short entry not in premium zone');
   104→    }
   105→
   106→    if (IMMUTABLE_RULES.LIQUIDITY_SWEEP_REQUIRED && !input.sweep) {
   107→      dqs.push('No liquidity sweep confirmed');
   108→    }
   109→
   110→    if (input.macro.vix.interpretation === 'PANIC') {
   111→      dqs.push('VIX in PANIC territory');
   112→    }
   113→
   114→    if (IMMUTABLE_RULES.KILL_ZONE_REQUIRED && input.killZone === 'NONE') {
   115→      dqs.push('Outside kill zone');
   116→    }
   117→
   118→    if (input.macro.newsFilter.noTradeWindow) {
   119→      dqs.push('High impact news window');
   120→    }
   121→
   122→    return dqs;
   123→  }
   124→
   125→  /**
   126→   * Structure Alignment score (max 30 pts).
   127→   * - HTF trend aligned: +10
   128→   * - Zone correct: +5
   129→   * - Price in OTE zone: +5
   130→   * - EMA stack aligned with direction: +5
   131→   * - VWAP confirms direction (long below VWAP = discount): +5
   132→   */
   133→  private scoreStructure(input: ScoreInput): number {
   134→    let score = 0;
   135→
   136→    if (input.htfAligned) score += 10;
   137→    if (input.zoneValid) score += 5;
   138→    if (input.isInOTE) score += 5;
   139→
   140→    // Indicator confluence
   141→    if (input.indicators) {
   142→      // EMA alignment
   143→      const ema = input.indicators.emaAlignment;
   144→      if (input.direction === 'LONG' && ema === 'BULLISH_STACK') score += 5;
   145→      else if (input.direction === 'SHORT' && ema === 'BEARISH_STACK') score += 5;
   146→
   147→      // VWAP confluence: longs entering below VWAP (discount), shorts above
   148→      if (input.direction === 'LONG' && input.indicators.priceVsVwap === 'BELOW') score += 5;
   149→      else if (input.direction === 'SHORT' && input.indicators.priceVsVwap === 'ABOVE') score += 5;
   150→    } else {
   151→      // Without indicators, fall back to original simpler scoring
   152→      if (input.zoneValid) score += 5; // extra zone weight
   153→      if (input.isInOTE) score += 5; // extra OTE weight
   154→    }
   155→
   156→    return Math.min(score, SCORE_MAXIMUMS.structureAlignment);
   157→  }
   158→
   159→  /**
   160→   * Judas Swing Quality score (max 25 pts).
   161→   * - Level rank S+/S: +10, A+/A: +8, B+/B: +5
   162→   * - Fast reintegration: +5
   163→   * - AMD confirmed: +5
   164→   * - CVD confirms reversal: +5
   165→   */
   166→  private scoreJudasSwing(input: ScoreInput): number {
   167→    let score = 0;
   168→
   169→    if (input.sweep) {
   170→      const rank = input.sweep.level.rank;
   171→      if (rank === 'S+' || rank === 'S') score += 10;
   172→      else if (rank === 'A+' || rank === 'A') score += 8;
   173→      else if (rank === 'B+' || rank === 'B') score += 5;
   174→
   175→      if (input.sweep.reintegrated && input.sweep.reintegrationSpeed <= 5) {
   176→        score += 5;
   177→      }
   178→    }
   179→
   180→    if (input.amd.confirmed) score += 5;
   181→
   182→    // CVD confluence
   183→    if (input.indicators) {
   184→      const cvd = input.indicators.cvdTrend;
   185→      if (input.direction === 'LONG' && cvd === 'BULLISH') score += 5;
   186→      else if (input.direction === 'SHORT' && cvd === 'BEARISH') score += 5;
   187→    }
   188→
   189→    return Math.min(score, SCORE_MAXIMUMS.judasSwingQuality);
   190→  }
   191→
   192→  /**
   193→   * Entry Quality score (max 25 pts).
   194→   * - FVG present: +5 (in OTE: +10)
   195→   * - FVG size >= 10: +3
   196→   * - FVG+OB overlap: +5
   197→   * - Valid OB: +5
   198→   * - Entry near volume profile POC or LVN: +2
   199→   */
   200→  private scoreEntry(input: ScoreInput): number {
   201→    let score = 0;
   202→
   203→    if (input.fvg && input.fvg.isValid) {
   204→      if (input.isInOTE) score += 10;
   205→      else score += 5;
   206→
   207→      if (math.isGte(input.fvg.size, 10)) score += 3;
   208→    }
   209→
   210→    if (input.fvgObOverlap) score += 5;
   211→
   212→    if (input.ob && input.ob.confirmed && !input.ob.mitigated) {
   213→      score += 5;
   214→    }
   215→
   216→    // Volume profile confluence
   217→    if (input.indicators && input.indicators.volumeProfile.lowVolumeNodes.length > 0) {
   218→      // Entry near a Low Volume Node (price will move fast through it) = good
   219→      const entryPrice = input.fvg?.midpoint ?? input.ob?.high ?? input.currentPrice;
   220→      const nearLVN = input.indicators.volumeProfile.lowVolumeNodes.some(
   221→        lvn => math.pointsDistance(lvn, entryPrice) < 5,
   222→      );
   223→      if (nearLVN) score += 2;
   224→    }
   225→
   226→    return Math.min(score, SCORE_MAXIMUMS.entryQuality);
   227→  }
   228→
   229→  /**
   230→   * Macro Context score (max 20 pts).
   231→   * - No high impact news: +5
   232→   * - VIX calm/normal: +3
   233→   * - DXY confirms direction: +4
   234→   * - Sentiment contrarian: +3
   235→   * - RSI divergence confirms: +5
   236→   */
   237→  private scoreMacro(input: ScoreInput): number {
   238→    let score = 0;
   239→
   240→    if (!input.macro.newsFilter.highImpactToday) score += 5;
   241→    if (input.macro.vix.level < 20) score += 3;
   242→
   243→    const dxyDir = input.macro.dxy.implication;
   244→    if (dxyDir !== 'NEUTRAL' && dxyDir === input.direction) score += 4;
   245→
   246→    if (input.macro.sentiment) {
   247→      if (input.macro.sentiment.contrarianSignal === input.direction) score += 3;
   248→    }
   249→
   250→    // RSI divergence confluence
   251→    if (input.indicators) {
   252→      const div = input.indicators.rsiDivergence;
   253→      if (input.direction === 'LONG' && div === 'BULLISH_DIV') score += 5;
   254→      else if (input.direction === 'SHORT' && div === 'BEARISH_DIV') score += 5;
   255→    }
   256→
   257→    return Math.min(score, SCORE_MAXIMUMS.macroContext);
   258→  }
   259→
   260→  private assignGrade(total: number): ScoreGrade {
   261→    if (total >= SCORE_GRADES['A+'].min) return 'A+';
   262→    if (total >= SCORE_GRADES['A'].min) return 'A';
   263→    if (total >= SCORE_GRADES['B+'].min) return 'B+';
   264→    if (total >= SCORE_GRADES['B'].min) return 'B';
   265→    return 'C';
   266→  }
   267→
   268→  private getSizing(grade: ScoreGrade): number {
   269→    return SCORE_GRADES[grade]?.sizing ?? 0;
   270→  }
   271→}
