     1→import type {
     2→  Direction,
     3→  EntryParams,
     4→  EntryType,
     5→  PartialExit,
     6→  TrailingStopConfig,
     7→  FairValueGap,
     8→  OrderBlock,
     9→  LiquidityLevel,
    10→  InstrumentConfig,
    11→  DealingRange,
    12→  AMDPattern,
    13→} from '../core/types.js';
    14→import * as math from '../utils/math.js';
    15→
    16→/**
    17→ * RiskCalculator — Position sizing, stop loss, and take profit calculation.
    18→ * Enforces maximum SL distance and minimum R:R ratio.
    19→ */
    20→export class RiskCalculator {
    21→  /**
    22→   * Calculate complete entry parameters for a trade signal.
    23→   *
    24→   * @param direction Trade direction
    25→   * @param fvg Best FVG for entry (if available)
    26→   * @param ob Best Order Block for entry (if available)
    27→   * @param amd AMD pattern (for SL placement)
    28→   * @param targets Opposing liquidity levels for TP
    29→   * @param range Dealing range
    30→   * @param instrument Instrument configuration
    31→   * @param capital Account capital
    32→   * @param riskPercent Risk per trade (e.g., 0.01 for 1%)
    33→   * @param sizingMultiplier Score-based sizing (0-1)
    34→   * @param vixMultiplier VIX-based sizing (0-1)
    35→   */
    36→  calculateEntryParams(
    37→    direction: Direction,
    38→    fvg: FairValueGap | null,
    39→    ob: OrderBlock | null,
    40→    amd: AMDPattern,
    41→    targets: readonly LiquidityLevel[],
    42→    range: DealingRange | null,
    43→    instrument: InstrumentConfig,
    44→    capital: number,
    45→    riskPercent: number,
    46→    sizingMultiplier: number,
    47→    vixMultiplier: number,
    48→  ): EntryParams | null {
    49→    // Determine entry type and price
    50→    const { entryType, entryPrice } = this.determineEntry(direction, fvg, ob);
    51→    if (entryPrice === null) return null;
    52→
    53→    // Calculate stop loss
    54→    const stopLoss = this.calculateStopLoss(
    55→      direction,
    56→      amd,
    57→      fvg,
    58→      ob,
    59→      range,
    60→      instrument.spread,
    61→    );
    62→
    63→    const slDistance = math.pointsDistance(entryPrice, stopLoss);
    64→
    65→    // Validate SL distance
    66→    if (math.isGreater(slDistance, instrument.maxSLPoints)) {
    67→      return null; // SL too wide
    68→    }
    69→
    70→    if (slDistance === 0) return null;
    71→
    72→    // Calculate take profits
    73→    const { tp1, tp2, tp3 } = this.calculateTakeProfits(
    74→      direction,
    75→      entryPrice,
    76→      slDistance,
    77→      targets,
    78→    );
    79→
    80→    // Calculate R:R (using TP1 as minimum)
    81→    const rr = math.div(math.pointsDistance(entryPrice, tp1), slDistance);
    82→    if (math.isLess(rr, 2)) return null; // Minimum 2R
    83→
    84→    // Calculate position size
    85→    const effectiveRisk = math.mul(riskPercent, math.mul(sizingMultiplier, vixMultiplier));
    86→    const riskAmount = math.mul(capital, effectiveRisk);
    87→    const positionSize = this.calculatePositionSize(
    88→      riskAmount,
    89→      slDistance,
    90→      instrument.pointValue,
    91→    );
    92→
    93→    if (positionSize <= 0) return null;
    94→
    95→    // Partial exits: 50% at TP1, 30% at TP2, 20% at TP3
    96→    const partialExits: PartialExit[] = [
    97→      { level: tp1, percent: 50, rMultiple: math.roundTo(math.div(math.pointsDistance(entryPrice, tp1), slDistance), 2) },
    98→      { level: tp2, percent: 30, rMultiple: math.roundTo(math.div(math.pointsDistance(entryPrice, tp2), slDistance), 2) },
    99→      { level: tp3, percent: 20, rMultiple: math.roundTo(math.div(math.pointsDistance(entryPrice, tp3), slDistance), 2) },
   100→    ];
   101→
   102→    // Trailing stop: activates at 2R, trails at 1R distance, steps by 0.5R
   103→    const trailingStop: TrailingStopConfig = {
   104→      activationR: 2,
   105→      trailDistance: math.mul(slDistance, 1),
   106→      stepSize: math.mul(slDistance, 0.5),
   107→    };
   108→
   109→    return {
   110→      type: entryType,
   111→      price: entryPrice,
   112→      stopLoss,
   113→      slDistance,
   114→      tp1,
   115→      tp2,
   116→      tp3,
   117→      riskReward: math.roundTo(rr, 2),
   118→      positionSize,
   119→      riskAmount: math.roundTo(riskAmount, 2),
   120→      riskPercent: math.roundTo(math.mul(effectiveRisk, 100), 2),
   121→      partialExits,
   122→      trailingStop,
   123→    };
   124→  }
   125→
   126→  /**
   127→   * Calculate position size.
   128→   * positionSize = riskAmount / (slDistance * pointValue)
   129→   */
   130→  calculatePositionSize(
   131→    riskAmount: number,
   132→    slDistance: number,
   133→    pointValue: number,
   134→  ): number {
   135→    const denominator = math.mul(slDistance, pointValue);
   136→    if (denominator === 0) return 0;
   137→    return Math.floor(math.div(riskAmount, denominator));
   138→  }
   139→
   140→  /**
   141→   * Calculate stop loss placement.
   142→   * For longs: below the Judas sweep low / OB low + spread buffer.
   143→   * For shorts: above the Judas sweep high / OB high + spread buffer.
   144→   */
   145→  calculateStopLoss(
   146→    direction: Direction,
   147→    amd: AMDPattern,
   148→    fvg: FairValueGap | null,
   149→    ob: OrderBlock | null,
   150→    _range: DealingRange | null,
   151→    spread: number,
   152→  ): number {
   153→    if (direction === 'LONG') {
   154→      // SL below the lowest relevant level (sweep candle, OB, or FVG)
   155→      // Do NOT use dealing range extremes — they are too wide
   156→      const candidates: number[] = [];
   157→
   158→      if (amd.manipulationSweep) {
   159→        candidates.push(amd.manipulationSweep.sweepCandle.low);
   160→      }
   161→      if (ob) {
   162→        candidates.push(ob.low);
   163→      }
   164→      if (fvg) {
   165→        candidates.push(fvg.low);
   166→      }
   167→
   168→      if (candidates.length === 0) return 0;
   169→
   170→      const lowest = Math.min(...candidates);
   171→      return math.sub(lowest, spread);
   172→    }
   173→
   174→    // SHORT
   175→    const candidates: number[] = [];
   176→
   177→    if (amd.manipulationSweep) {
   178→      candidates.push(amd.manipulationSweep.sweepCandle.high);
   179→    }
   180→    if (ob) {
   181→      candidates.push(ob.high);
   182→    }
   183→    if (fvg) {
   184→      candidates.push(fvg.high);
   185→    }
   186→
   187→    if (candidates.length === 0) return 0;
   188→
   189→    const highest = Math.max(...candidates);
   190→    return math.add(highest, spread);
   191→  }
   192→
   193→  /**
   194→   * Calculate three take-profit levels.
   195→   * TP1: Nearest opposing liquidity or 2R (50% exit)
   196→   * TP2: Second target or 3R (30% exit)
   197→   * TP3: PWH/PWL or AMD distribution target or 4R (20% exit, trailing)
   198→   */
   199→  calculateTakeProfits(
   200→    direction: Direction,
   201→    entryPrice: number,
   202→    slDistance: number,
   203→    targets: readonly LiquidityLevel[],
   204→  ): { tp1: number; tp2: number; tp3: number } {
   205→    const sortedTargets = [...targets]
   206→      .filter(t => {
   207→        if (direction === 'LONG') {
   208→          return ['BSL', 'EQH', 'PWH', 'PDH', 'ASIAN_HIGH'].includes(t.type) &&
   209→            math.isGreater(t.price, entryPrice);
   210→        }
   211→        return ['SSL', 'EQL', 'PWL', 'PDL', 'ASIAN_LOW'].includes(t.type) &&
   212→          math.isLess(t.price, entryPrice);
   213→      })
   214→      .sort((a, b) => {
   215→        const distA = math.pointsDistance(a.price, entryPrice);
   216→        const distB = math.pointsDistance(b.price, entryPrice);
   217→        return distA - distB;
   218→      });
   219→
   220→    // Default R-multiples
   221→    const defaultTP1 = direction === 'LONG'
   222→      ? math.add(entryPrice, math.mul(slDistance, 2))
   223→      : math.sub(entryPrice, math.mul(slDistance, 2));
   224→
   225→    const defaultTP2 = direction === 'LONG'
   226→      ? math.add(entryPrice, math.mul(slDistance, 3))
   227→      : math.sub(entryPrice, math.mul(slDistance, 3));
   228→
   229→    const defaultTP3 = direction === 'LONG'
   230→      ? math.add(entryPrice, math.mul(slDistance, 4))
   231→      : math.sub(entryPrice, math.mul(slDistance, 4));
   232→
   233→    // Use liquidity targets if available, fallback to R-multiples
   234→    const tp1 = sortedTargets[0]?.price ?? defaultTP1;
   235→    const tp2 = sortedTargets[1]?.price ?? defaultTP2;
   236→    const tp3 = sortedTargets[2]?.price ?? defaultTP3;
   237→
   238→    return { tp1, tp2, tp3 };
   239→  }
   240→
   241→  /** Determine entry type and price from available zones */
   242→  private determineEntry(
   243→    direction: Direction,
   244→    fvg: FairValueGap | null,
   245→    ob: OrderBlock | null,
   246→  ): { entryType: EntryType; entryPrice: number | null } {
   247→    // FVG + OB overlap: enter at FVG midpoint
   248→    if (fvg && ob && fvg.isValid) {
   249→      return { entryType: 'FVG', entryPrice: fvg.midpoint };
   250→    }
   251→
   252→    // FVG only: enter at midpoint
   253→    if (fvg && fvg.isValid) {
   254→      return { entryType: 'FVG', entryPrice: fvg.midpoint };
   255→    }
   256→
   257→    // OB only: enter at OB boundary
   258→    if (ob && ob.confirmed && !ob.mitigated) {
   259→      const price = direction === 'LONG'
   260→        ? ob.high // Enter at OB high for longs (price coming back up into OB)
   261→        : ob.low;  // Enter at OB low for shorts
   262→      return { entryType: 'ORDER_BLOCK', entryPrice: price };
   263→    }
   264→
   265→    return { entryType: 'FVG', entryPrice: null };
   266→  }
   267→}
