     3→/**
     4→ * Generate a sequence of candles with a bullish trend (HH/HL pattern).
     5→ * Uses fast oscillation on top of an upward drift to produce clear swing points.
     6→ * Prices start around 5000 and trend upward.
     7→ */
     8→export function generateBullishTrendCandles(count: number = 50): Candle[] {
     9→  const candles: Candle[] = [];
    10→  // NY Open time: 9:30 AM ET = 14:30 UTC
    11→  const startTime = new Date('2024-03-04T14:30:00Z').getTime(); // Monday
    12→
    13→  for (let i = 0; i < count; i++) {
    14→    // Upward trend (1.5 per candle) + fast oscillation (period ~8 candles)
    15→    const trendComponent = i * 1.5;
    16→    const oscillation = Math.sin(i * 0.8) * 8;
    17→    const mid = 5000 + trendComponent + oscillation;
    18→
    19→    const bodySize = 2 + Math.abs(Math.sin(i * 1.1)) * 3;
    20→    const isBullishCandle = Math.sin(i * 0.8 + 0.4) > 0;
    21→    const open = isBullishCandle ? mid - bodySize / 2 : mid + bodySize / 2;
    22→    const close = isBullishCandle ? mid + bodySize / 2 : mid - bodySize / 2;
    23→    const high = Math.max(open, close) + 1 + Math.abs(Math.sin(i * 0.7)) * 2;
    24→    const low = Math.min(open, close) - 1 - Math.abs(Math.cos(i * 0.7)) * 2;
    25→
    26→    candles.push({
    27→      timestamp: startTime + i * 15 * 60 * 1000, // 15-min candles
    28→      open: Math.round(open * 100) / 100,
    29→      high: Math.round(high * 100) / 100,
    30→      low: Math.round(low * 100) / 100,
    31→      close: Math.round(close * 100) / 100,
    32→      volume: 1000 + i * 10,
    33→    });
    34→  }
    35→
    36→  return candles;
    37→}
