   141→/**
   142→ * Generate candles showing an Order Block pattern.
   143→ * Last bearish candle before a bullish displacement.
   144→ */
   145→export function generateOrderBlockCandles(): Candle[] {
   146→  const startTime = new Date('2024-03-04T14:30:00Z').getTime();
   147→  return [
   148→    { timestamp: startTime, open: 5020, high: 5025, low: 5018, close: 5022, volume: 1000 },
   149→    { timestamp: startTime + 900000, open: 5022, high: 5026, low: 5019, close: 5024, volume: 1100 },
   150→    // Bearish candle (this will be the OB)
   151→    { timestamp: startTime + 1800000, open: 5024, high: 5026, low: 5015, close: 5016, volume: 1500 },
   152→    // Strong bullish displacement
   153→    { timestamp: startTime + 2700000, open: 5016, high: 5045, low: 5015, close: 5042, volume: 4000 },
   154→    { timestamp: startTime + 3600000, open: 5042, high: 5050, low: 5040, close: 5048, volume: 2000 },
   155→    { timestamp: startTime + 4500000, open: 5048, high: 5055, low: 5045, close: 5052, volume: 1800 },
   156→  ];
   157→}
   158→
   159→/**
   160→ * Simple ranging candles (no clear trend).
   161→ */
   162→export function generateRangingCandles(count: number = 30): Candle[] {
   163→  const candles: Candle[] = [];
   164→  const startTime = new Date('2024-03-04T14:30:00Z').getTime();
   165→  let base = 5050;
   166→
   167→  for (let i = 0; i < count; i++) {
   168→    const swing = Math.sin(i * 0.4) * 15;
   169→    const open = base + swing;
   170→    const close = open + (Math.random() - 0.5) * 6;
   171→    const high = Math.max(open, close) + Math.random() * 3;
   172→    const low = Math.min(open, close) - Math.random() * 3;
   173→
   174→    candles.push({
   175→      timestamp: startTime + i * 15 * 60 * 1000,
   176→      open: Math.round(open * 100) / 100,
   177→      high: Math.round(high * 100) / 100,
   178→      low: Math.round(low * 100) / 100,
   179→      close: Math.round(close * 100) / 100,
   180→      volume: 1000 + Math.floor(Math.random() * 500),
   181→    });
   182→    base = 5050; // Stays centered around 5050
   183→  }
   184→
   185→  return candles;
   186→}
